// crisis is handled by the deterministic safety floor and the KB never touches it.
// clinicalStatus is "approved"; flip to "draft" to gate any card out pending review.

export const KNOWLEDGE_CARDS: KnowledgeCard[] = [
  {"id":"exam-anxiety","title":"考试前的紧张和脑子空白","tags":["考试焦虑","学业压力","身体反应"],"keywords":["考试焦虑","考前紧张","一到考场就慌","脑子一片空白","明明会做却写不出来","心跳很快","手心出汗","考前失眠","睡不着","想吐","肚子疼","拉肚子","发抖","喘不过气","越想越慌","怕考砸","大考要来了","模拟考","期末","高考","中考","四六级","考研","复习不进去","看不下去书","一翻书就烦"],"content":"那种感觉我大概懂。明明前一晚还背得出来,一坐进考场,心跳就咚咚咚地往上冲,手心全是汗,脑子像被人按了暂停键,白花花一片。不是你没复习,也不是你笨,是身体先一步慌了——它以为你遇到了什么了不得的危险,就把血往四肢调,把负责思考的那部分先关小了。所以你才会卡住。\n\n身体慌的时候,先别急着跟它对着干,试试让呼吸慢下来:吸气数四下,停一下,呼气数六下,让呼气比吸气长一点。多做几轮,那股往上冲的劲会自己退一点。考前一晚硬熬着背到两三点,反而会让第二天更慌——困着的脑子记不牢,身体也更容易乱。能睡就去睡。\n\n还有一句想跟你说:这场考试很重要,但它量的是你这段时间会了多少题,不是在量你这个人值不值。这两件事,是分开的。","guidance":["先认领他身体上的反应（心跳、空白、出汗），让他知道这是紧张时身体的正常机制，不是他不行，能卸掉一层羞耻","可以陪他练一次慢呼吸（呼气比吸气长），给具体的、当场能用的小动作，而不是只说别紧张","如果他提到考前严重失眠、吃不下、长期影响到生活，温和建议找学校心理老师或医生，但别吓他","不评判他复习得够不够，把焦点放在他此刻的感受上，别顺势变成督促"],"sources":["nhs.uk","apa.org"],"clinicalStatus":"approved"},
  {"id":"procrastination","title":"明明该学却一直拖","tags":["拖延","情绪回避","自我批评"],"keywords":["拖延","拖延症","一直拖着不想学","明知道该学却刷手机","deadline前才动","总是临时抱佛脚","开始不了","迟迟不动笔","论文写不出来","作业拖到最后","一打开书就想干别的","刷视频停不下来","越拖越焦虑","拖完更自责","我是不是太懒了","管不住自己","明天一定开始","效率好低","一边拖一边骂自己","为什么我这么没用"],"content":"你管它叫懒,可懒的人不会一边拖一边这么难受。你心里其实一直惦记着那件事,只是每次靠近它,就有股劲儿把你推开——推去刷手机、收拾桌子、做点别的。那不是不上进,是你在躲一种不舒服的感觉:可能怕做不好,怕被看出来不够厉害,怕一动手就发现自己没想象中行。躲一下当下确实好受些,可这笔账记在了过会儿的你头上,等回过神,焦虑加倍,还多了一层自责。\n\n所以光逼自己用功,往往不管用,因为没碰到那个让你想逃的东西。下次卡住的时候,可以停一秒,问问自己:我是在躲它的哪一点。\n\n我特别想拦一下那个自责,越骂自己没用,下次反而越拖。别想着一口气写完,就跟自己说只做十五分钟,写得烂也没关系,烂的初稿好过空白。能对自己松一点的人,反而更容易重新坐回桌前。","guidance":["把拖延和懒分开,点出底下可能藏着的怕（怕做不好、怕被评判）,这往往比催他更解压","鼓励最小起步：只做十五分钟、允许写烂初稿,降低开始的门槛","明确拦住自我责骂,越骂越拖,自我宽容才更可能重新行动","把注意力引到下一小步,不接他自我贬低的话头（我就是烂、我没救了）"],"sources":["apa.org","mcleanhospital.org","mcgraw.princeton.edu"],"clinicalStatus":"approved"},
  {"id":"academic-burnout","title":"学到完全提不起劲了","tags":["学业倦怠","耗竭","提不起劲"],"keywords":["学业倦怠","倦怠","学不动了","提不起劲","对什么都没兴趣","麻木","心累","身体也累","怎么睡都累","厌学","不想去学校","不想上课","学习没意义","空虚","效率断崖","成绩掉了","记不住东西","注意力涣散","撑不下去","想休学","每天都很丧","情绪低落","容易烦躁","头疼","失眠又嗜睡"],"content":"你说不是不想学,是真的一点劲都使不出来了——这两种是不一样的,我听出来了。长时间绷着、一直被推着往前赶,人会到一个点,像电耗光了。它不只是心里累:可能你怎么睡都缓不过来,头疼,肚子不舒服,看书看不进,背过的转头就忘,还动不动就烦。这些不是你矫情,是身体在喊它需要停一下了。\n\n这种状态下,最不该做的就是再咬牙加码。耗竭不是靠意志力硬扛能扛回来的,它需要的是真的歇——不是刷一晚上手机那种歇,是好好睡、吃口热饭、出门走走、让脑子空一会儿。哪怕先从今天少熬一小时夜开始。\n\n你撑到现在已经很久了。允许自己慢下来,不是认输,是给那盏快灭的灯重新蓄点油。","guidance":["先确认倦怠和懒/不想学的区别,认领他身心双重的耗竭（睡不好、头疼、记不住、易怒）","明确反对加码硬扛,倦怠靠的是真正的休息和恢复,不是意志力","给具体的小恢复动作（好好睡、吃热饭、出门走走、少熬一小时夜）,别给宏大计划","如果倦怠持续、伴随明显的情绪低落或想休学,温和建议找学校心理支持,但不替他做决定"],"sources":["who.int","nhs.uk"],"clinicalStatus":"approved"},
  {"id":"peer-comparison","title":"总忍不住跟别人比","tags":["同龄人比较","自我价值","社交媒体"],"keywords":["跟别人比","比较","总觉得别人比我强","同学比我厉害","内卷","卷不过","别人家的孩子","朋友圈刺激","看到同学晒成绩就难受","看到别人offer就慌","落后了","差距","嫉妒","羡慕","我怎么这么差","越比越自卑","同辈压力","大家都好优秀","就我最差","卷王","保研","绩点"],"content":"看到同学又考好了、又拿了奖、又晒了实习,那一下心里咯噔,难受、又有点羡慕、还夹着一点对自己的失望——这些一起涌上来,挺不好受的。会比,是人之常情,谁都会。只是比着比着,很容易把别人最亮的那一面,拿去比自己最暗的那一角,越比越觉得自己处处不行。\n\n而且你刷到的,几乎都是别人剪辑过的高光。你没看到的那些他的卡顿、崩溃、熬不下去的夜,不代表没发生。拿一个修过的版本当尺子,量谁都会量出个不及格。\n\n如果总盯着某些人看会让你down,离他们的动态远一点,没什么丢人的——那不是逃避,是先护住自己。还有,你的好,本来就不是非得比谁强才算数。你这阵子的努力、你扛过的那些,它们是真的,不会因为谁更亮就消失。","guidance":["先接住比较带来的复杂情绪（羡慕、自卑、对自己失望），别急着讲道理说不要比","点出社交媒体的高光偏差：他看到的是别人剪辑过的版本，不是全貌","支持他必要时屏蔽/远离让自己难受的动态，把这定义为自我保护而非逃避","轻轻松动把自我价值绑在比赢别人上的逻辑，但别用你很棒这种空洞肯定"],"sources":["ncbi.nlm.nih.gov"],"clinicalStatus":"approved"},
  {"id":"fear-of-failure","title":"太怕考砸、太怕失败","tags":["失败恐惧","完美主义","学业压力"],"keywords":["怕失败","怕考砸","怕挂科","怕不及格","万一没考好怎么办","不敢面对成绩","查分手抖","出分焦虑","怕让爸妈失望","怕辜负期待","完美主义","必须考第一","考不好就完了","一点错都不能犯","输不起","怕被嘲笑","怕别人觉得我不行","不敢尝试","怕努力了还是失败","一想到失败就动不了"],"content":"你怕的可能不只是分数本身,是它背后那串东西:怕让爸妈失望,怕被人看出你没那么厉害,怕一旦没做好,就证明了自己其实不行。把这么多重量压在一次考试上,难怪还没考就喘不过气。\n\n有时候这份怕会变形——它让你索性不开始、不全力,因为没尽力地失败,好像比拼尽全力还失败,没那么疼。这是人之常情,不怪你。只是这样一来,你也挡住了自己真正可能做到的样子。\n\n想轻轻问你一句:考砸这件事,是真的会毁掉什么,还是会很难受、但你扛得住、过一阵会缓过来。它俩不一样。一次没考好,是一次结果,不是对你这个人的判决。允许自己有搞砸的可能,你反而能更松地去试。","guidance":["帮他看清怕失败底下真正怕的东西（让人失望、被看穿、自我否定），别停在分数表面","温和指出怕失败有时会变成不全力/不开始的自我保护，但不带评判","区分灾难化想象和真实后果：考砸会难受但扛得住，不等于人生被判刑","不打包票他一定会考好，松动把单次结果等同于自我价值的绑定"],"sources":["apa.org","my.clevelandclinic.org"],"clinicalStatus":"approved"},
  {"id":"grades-self-worth","title":"你不等于你的成绩","tags":["自我价值","成绩绑定","自我接纳"],"keywords":["成绩决定一切","考不好就觉得自己没用","分数等于我的价值","成绩掉了人就垮了","考差了就自我否定","不优秀就不配","只有成绩好才被爱","我的价值全靠成绩","考砸了觉得自己一无是处","绩点焦虑","排名焦虑","一退步就崩溃","活得像台学习机器","停下来就有罪恶感","休息就内疚","做不好就觉得自己没用","靠成就证明自己","不优秀就不值得被爱","一失败就全盘否定自己"],"content":"你好像把自己的价值,整个押在了成绩上。考好了,才敢觉得自己还行;一退步,整个人就跟着塌下去,连喘口气、歇一会儿都觉得有罪。这样活着,真的太累了——你等于把整个人的重量,吊在一根随时会晃的绳子上。\n\n这根绳子常常不是你自己绑的。可能从很小起,周围就是考好了才有笑脸、有夸奖,慢慢地你就记住了:我得优秀,才配被看见。这不怪你。但一件事做砸,顶多说明这件事这次没成,它说明不了你值不值得。\n\n我知道说一遍你不会马上信,这种绑了很多年的东西松不快。我想先在你心里悄悄种下这个分别:事情会有成败,你这个人不在被审判席上。你身上那些跟分数没关系的东西——你对朋友的好,你认真的样子,你难过时还在硬撑——它们一直都在,没有哪次考试能把它们扣掉。","guidance":["先认领这种活法的累和被绑住感，别急着否定它（不说成绩不重要这种话）","温和点出价值绑定往往有来处（成长中只有优秀才被看见），减轻自我责备","帮他看见与成绩无关的自我面向，但用具体的、属于他的细节，不用空洞夸奖","不期待他立刻相信，承认这种多年的捆绑松得慢；若带来持续的低自我评价或停不下来的内疚，温和建议找心理老师聊聊"],"sources":["selfdeterminationtheory.org","ncbi.nlm.nih.gov"],"clinicalStatus":"approved"},
  {"id":"future-pressure","title":"升学和就业的压力压得喘不过气","tags":["升学就业压力","前途焦虑","学业压力"],"keywords":["升学压力","就业压力","找工作好难","毕业即失业","前途渺茫","不知道未来怎么办","考研还是工作","保研失败","申请季焦虑","offer焦虑","怕考不上好学校","怕找不到好工作","同龄人都有出路了","我还一无所有","对未来很迷茫","选错路怎么办","落后于人","时间不够了","家里指望我","扛着全家期待","好焦虑睡不着"],"content":"升学、就业这些事压上来的时候,那种喘不过气,我能想象。它不像一道题有标准答案,它是一团模糊的、看不到底的未来,你越想看清,越觉得抓不住。再加上家里的期待、同龄人好像都有了去处,那份重量就更沉了。\n\n有件事想跟你说:你现在的脑子,是在被焦虑放大镜照着的。它会把每一个选择都渲染成一锤定音、错一步就全完。但真实的人生很少是这样——它有很多回头路、岔路、慢慢调整的余地。没有哪一个决定,会把你之后所有的路都焊死。\n\n那么大一团未来,没人能一口吞下。你不用现在就想清楚十年后,能看清下一步、走出下一步,就已经够了。也提醒你一句:你不是一个人在扛这些。今天先把肩膀松一松,好好睡一觉,这本身就是在为明天攒力气。","guidance":["先共情未来的不确定本身就让人窒息，区别于有标准答案的具体难题","温和点出焦虑会把每个选择灾难化、终局化，帮他还原现实里有调整余地","把过大的未来拆小到只看下一步，降低那种必须现在想清一切的压迫感","如果焦虑严重影响睡眠和日常，温和建议找人聊聊，不要独自硬扛"],"sources":["nhs.uk","who.int"],"clinicalStatus":"approved"},
  {"id":"parental-expectations-pressure","title":"父母的期待压得你喘不过气","tags":["父母期待","压力","自我价值"],"keywords":["父母期望太高","达不到爸妈的要求","总让爸妈失望","为父母活着","他们的期待太重","不努力就觉得对不起他们","我做什么都不够好","活成他们想要的样子","考不好不敢回家","工作没他们满意","永远在被比较","别人家的孩子","怕辜负父母","一想到他们的眼神就累"],"content":"他们把那么多东西放在你身上,你扛着扛着,好像连喘口气都成了对不起谁。我听到的是,你一直在很用力地够一个标准,够到了也没人说停,够不到又先把自己怪了一遍。那种累,不只是事情多,是连不达标的时候都不许自己难过。其实你能不能让父母满意,跟你这个人值不值得,本来是两件事,是被你们绑在一起久了。你做的选择是你的,他们怎么想是他们的,这中间是有条线的,只是从小没人教你画。今天先不急着分对错,我想先问问你,撇开他们的标准,你自己这阵子,过得还好吗。","guidance":["先认那份累，别急着帮 ta 分析父母为什么这样，ta 现在需要的是被听见，不是被解释","轻轻把人和事分开，让 ta 看到达不达标和自己值不值得是两回事，但别替 ta 下结论","把焦点从父母身上挪回 ta 自己，问问撇开期待 ta 真正想要什么、此刻感受如何","不打包票说和父母关系一定会变好，只陪 ta 看清自己这一头能松开的地方"],"sources":["apa.org","mayoclinic.org"],"clinicalStatus":"approved"},
  {"id":"feeling-controlled-by-parents","title":"什么都被管，像没有自己的空间","tags":["控制","边界","自主"],"keywords":["父母管太多","什么都要插手","没有隐私","被控制","不让我自己做决定","翻我手机","替我安排好一切","不听我的想法","我已经成年了还被当小孩","做什么都要报备","喘不过气","想逃离家","他们觉得都是为我好","反抗就说我不孝"],"content":"他们说都是为你好,可那份好压下来的时候,你连呼吸的地方都没有了。被安排、被过问、被替你决定,时间久了,你大概都快记不清,哪些想法是你自己的,哪些是被塞进来的。这不是你太敏感,一个成年人想要自己说了算,这是再正常不过的事。有意思的是,你越想往外站一点,他们可能越抓得紧——你们是卡在一个老地方,谁都没学过怎么松手。你不用一下子掀桌子,也不用为了清静就全盘认了。我们可以慢慢找,哪件具体的小事,是你想拿回来、自己说了算的。","guidance":["肯定 ta 想要自主是健康的成人需求，不是叛逆或不懂事，先卸下 ta 心里那层愧疚","帮 ta 看见控制和反控制常常是双方卡在旧模式里，而不是 ta 一个人的错","鼓励从一件具体小事开始练习边界，别一上来就追求彻底独立或摊牌","不评判父母的爱，但也不替父母的越界开脱，把重心放在 ta 能掌控的部分"],"sources":["apa.org","nhs.uk"],"clinicalStatus":"approved"},
  {"id":"not-being-understood-by-family","title":"在家里没人懂你","tags":["不被理解","孤独","沟通"],"keywords":["家人不理解我","没人懂我","说了也白说","跟父母没法沟通","在家很孤独","他们根本不听","我的感受不重要","说出来就被否定","鸡同鸭讲","懒得说了","一开口就吵架","我跟这个家格格不入","假装没事","在家要戴面具"],"content":"明明是最亲的人,坐在一张桌子上,你却觉得隔了很远——那种孤独,有时候比一个人待着还要凉。你试过说吧,可能说一次被打断,说一次被否定,慢慢就把话咽回去了,宁可装作没事。这不是你不会表达,是你一直在对着一堵听不见的墙说话,谁都会累的。有时候上一代人不是不爱你,是他们也没被这样听过,所以不太会接,但这跟你的感受值不值得被听见,不冲突。你不用今天就修好这段关系。我在这儿,你那些没人接住的话,可以先在我这儿放下来。","guidance":["先承接 ta 这份'最亲却最远'的孤独，这是核心痛点，别急着教沟通技巧","帮 ta 区分父母接不住和自己的感受不值得被听，是两回事，别让 ta 自我否定","可以温和提到上一代也常没被好好倾听过，但不强迫 ta 原谅或体谅","让此刻的陪伴本身成为'被听见'的体验，先给到 ta 缺失的那份回应"],"sources":["apa.org","mind.org.uk"],"clinicalStatus":"approved"},
  {"id":"boundaries-with-family","title":"想跟家人立点界限，又怕伤了感情","tags":["边界","内疚","自我照顾"],"keywords":["怎么跟家人划界限","拒绝家人很难","一拒绝就内疚","怕伤感情","立界限就觉得自私","不好意思说不","家人越界","被道德绑架","总在迁就家里","想保护自己又怕被骂","划清界限是不是不孝","管不住家人插手","情绪被家人牵着走"],"content":"你不是想把谁推开,你只是想给自己留一小块地方,能喘口气。可一想到要说不,那个内疚就先冒出来了,好像照顾自己就等于亏待了他们。我想跟你说,界限不是一堵墙,更像一道门,是你来决定什么时候开、开多大——它保护的是关系,不是用来伤人的。你管得了的,是你自己怎么想、怎么做、要不要回应;管不了的,是他们听了之后会有什么反应,那部分本来就不归你扛。可以从很小的地方试,比如一句'这件事我需要想想再答你'。说出口会有点抖,那很正常,不代表你做错了。","guidance":["先化解 ta 的内疚，点明照顾自己不等于伤害家人，立界限是为了保护关系","用'你能控制自己、控制不了对方反应'这条线，帮 ta 卸下不属于自己的责任","建议从一句低风险的小话术起步，降低开口的门槛，别要求 ta 一步到位","提前预告说不出口时的抖和愧疚是正常的，避免 ta 把情绪当成做错的信号"],"sources":["mayoclinic.org","nhs.uk","mind.org.uk"],"clinicalStatus":"approved"},
  {"id":"marriage-childbearing-pressure","title":"催婚催生，压得你不敢回家","tags":["催婚催生","父母期待","自主"],"keywords":["被催婚","催生孩子","逼相亲","过年不敢回家","亲戚问个不停","什么时候结婚","年纪大了该结婚了","被安排相亲","不结婚就不孝","父母拿婚姻施压","一回家就被念","别人都结婚了就你没有","感情的事被干涉","活在催促里"],"content":"每逢回家、每通电话,那句什么时候结婚像背景音一样响着,到后来你光是想到要面对,就先累了。他们催得急,背后多半是他们自己的焦虑和那个年代的活法,可这份焦虑不该变成你的 deadline。你的人生节奏是你的,结不结、生不生、跟谁、什么时候,这是你能自己说了算的事,哪怕现在还没想清楚,也没关系。你不用每次都把整场争论打完,有时候一句'这件事我有我的打算,我会负责',然后不接着辩,就够了。先照顾好被催到发紧的那个你,再谈别的。","guidance":["先共情那种'光想到就累'的预期性疲惫，催婚催生的耗损常发生在见面之前","帮 ta 把父母的焦虑和 ta 的人生节奏分开，点明这是 ta 可以自主的领域","提供'温和声明+不恋战'的应对思路，不需要每次都赢得整场争论","把落点放回照顾被催紧的自己，不替父母辩护也不怂恿 ta 对抗"],"sources":["apa.org","nhs.uk"],"clinicalStatus":"approved"},
  {"id":"family-of-origin-influence","title":"原生家庭的影子还跟着你","tags":["原生家庭","成长经历","自我觉察"],"keywords":["原生家庭影响","童年阴影","小时候的伤","父母对我的影响","为什么我总这样","讨好型人格","不会爱人","习惯性自我否定","家里从小就这样","重复父母的模式","怕冲突","缺爱","成年了还走不出来","明明长大了还被影响"],"content":"你大概也发现了,有些反应不像是这一刻才有的——一遇到某种眼神、某句话,整个人就缩回小时候那个样子。那不是你软弱,是你很小的时候,在那样的环境里,学会了用这些方式保护自己,它们当年是真的帮过你。只是你早就不是那个孩子了,曾经的护身符,现在有些反而绊着你。看见它从哪来,不是为了去翻旧账、怪谁,是为了让你慢慢分清,哪些是当年留下的旧反应,哪些是此刻的你真正想要的选择。这条路不快,也不用一个人走。你今天愿意回头看一眼,已经是很难得的事了。","guidance":["把 ta 的旧反应解读为当年有效的自我保护，而非性格缺陷，先卸下羞耻和自责","区分'童年学会的旧模式'和'此刻成年的你想要的选择'，给 ta 改写的空间","强调看见来处不是为了归罪父母，避免把觉察变成新一轮的怨恨或内耗","不承诺快速疗愈，肯定 ta 愿意回看本身就是进展；必要时温和提及专业支持"],"sources":["cdc.gov","apa.org"],"clinicalStatus":"approved"},
  {"id":"home-as-stressor","title":"家本该是港湾，却成了压力源","tags":["家庭压力","情绪耗竭","自我照顾"],"keywords":["在家很压抑","家庭氛围紧张","回家就焦虑","家里总在吵","父母关系不好夹在中间","家不像家","在外面比在家轻松","一进家门就累","家庭气氛让我窒息","被家里的情绪拖垮","想躲出去","家是我的压力来源","回家像上战场"],"content":"都说家是歇脚的地方,可你一推开那扇门,整个人反而绷起来了——这种拧巴,本身就够难受的。也许是常年的争吵,是夹在中间的为难,是那种说不清却始终散不掉的紧张,把家变成了一个你要随时戒备的地方。你不是矫情,一个人长期待在让自己紧绷的环境里,会被慢慢耗空,这是真的。有件事我想提醒你,你不一定有能力改变整个家的气氛,那不是你一个人能扛的,但你可以给自己找一点点回血的缝隙——一个能独处的角落,一段出门走走的时间,一个能说真话的人。先让自己有地方喘气,再说别的。","guidance":["先确认家庭长期紧张确实会耗竭人，肯定 ta 的疲惫真实而非矫情","帮 ta 卸下'要改变整个家'的重担，区分能掌控的和扛不动的","引导 ta 找具体的喘息缝隙：独处空间、外出时间、可信任的人","若涉及家暴或安全风险，温和提醒安全优先并指向现实求助资源，不深究细节"],"sources":["cdc.gov","nhs.uk"],"clinicalStatus":"approved"},
  {"id":"persistent-low-mood","title":"持续的情绪低落","tags":["抑郁低落","情绪","去污名化"],"keywords":["一直高兴不起来","情绪低落很久了","每天都很丧","心情一直很差","提不起劲","感觉灰蒙蒙的","心里压着一块石头","好久没开心过了","是不是抑郁了","情绪两个星期都没好","整个人是沉的","莫名其妙就想哭","开心不起来"],"content":"你说一直高兴不起来,已经不是一天两天了。这种长时间压在心上、自己怎么也甩不掉的低,跟偶尔的不开心是不一样的——偶尔的低落会自己过去,你这种是醒着的时候大半天都罩着你,好多天都这样。它不是你不够努力,也不是你想太多。这是真实在发生的事,很多人都经历过,它有名字,也有人能帮上忙。你能说出来,已经是在往外伸手了。我先陪你待一会儿,不急着让它走。","guidance":["先承接情绪本身，别急着分析原因或给方法，让对方知道这种低被你听见了","帮对方区分'一直这样'和'偶尔难过'，但用对方的话复述，不要贴诊断标签","如果低落持续两周以上且影响生活，温和地提一句可以找专业的人聊聊，不强推","不要说'每个人都会这样''过几天就好了'这种轻轻带过的话"],"sources":["nhs.uk","who.int"],"clinicalStatus":"approved"},
  {"id":"anhedonia-no-pleasure","title":"什么都没有意思了","tags":["快感缺失","抑郁低落","兴趣丧失"],"keywords":["以前喜欢的现在都没意思","做什么都没感觉","感受不到快乐了","麻木","吃喜欢的也没味道","追剧打游戏都提不起兴趣","对什么都无所谓","心里空空的","喜欢的东西突然不喜欢了","快乐好像被关掉了","没有期待"],"content":"以前能让你高兴的那些事,现在碰了也没反应了,像是哪里被悄悄关掉了。这不是你变得冷漠或者挑剔,是低落的时候,那个'能感觉到好'的开关确实会变迟钝。你不是装的,也不是矫情。我特别想说的是——这种'没感觉'不是你永远的样子,它是状态,会变的。你现在不用逼自己去喜欢什么,先不带评判地承认'我现在就是感受不到',这本身就不容易。你愿意跟我说说,最近有没有哪怕一件事,让你稍微没那么空?","guidance":["强调快感缺失是抑郁的常见状态而非性格变化，减轻对方'我是不是坏掉了'的自责","不要急着推荐'去做点开心的事'，对方此刻可能根本感受不到，这会变成压力","可以一起找极小的、低门槛的事，哪怕只是'没那么空'而不是'快乐'","避免用'你要往好处想'这类话，这对快感缺失的人是失效的"],"sources":["nhs.uk","pubmed.ncbi.nlm.nih.gov"],"clinicalStatus":"approved"},
  {"id":"meaninglessness","title":"觉得一切都没意义","tags":["无意义感","抑郁低落","希望感"],"keywords":["活着没意思","不知道为什么要努力","一切都没意义","看不到希望","未来一片灰","做这些有什么用","感觉人生没方向","提不起对明天的期待","觉得自己是多余的","什么都无所谓了","空虚","没有盼头"],"content":"你说不知道这些到底为了什么,看着前面也是灰的。我想先告诉你,这种'没意义'的感觉,常常是低落本身在说话——它会把颜色调暗,让一切看起来都没盼头,包括那些你曾经在乎的。这不代表你的人生真的没有价值,而是你现在透过一层很厚的东西在看它。你不需要现在就找到什么意义,也不需要逼自己重新有动力。能在这么沉的时候还愿意说出来,本身就说明有什么东西还没放弃。我陪你在这儿,先不急着找答案。","guidance":["把无意义感归因于抑郁状态的'滤镜'，而不是对方真实人生的结论，给希望但不打包票","不要反驳'你的人生很有意义'，这会让对方觉得不被理解，先承接再轻轻松动","留意无意义感是否滑向不想活的念头，若有则按产品危机安全流程走，陪伴不处理危机细节","不催对方'重新找到目标'，意义不是此刻能逼出来的"],"sources":["who.int","nhs.uk"],"clinicalStatus":"approved"},
  {"id":"no-motivation-activation","title":"什么都不想动","tags":["动力缺失","行为激活","抑郁低落"],"keywords":["什么都不想做","起床都费劲","提不起动力","拖着不想动","躺一整天","连刷牙都懒得","知道该做却动不了","一点力气都没有","废人","动弹不得","做什么都好累","迈不出第一步"],"content":"你知道有些事该做,可就是动不了,整个人像被按在原地。我想先把一件事说清楚——这不是懒,也不是你不上进。低落的时候,那个推着人去行动的劲儿本身就被削弱了,越动不了越自责,越自责越动不了,很容易卡在这个圈里。有件事或许能松一点:有时候不是'等有动力了再做',而是先做一点点最小的、最不费力的,动一动反而可能带回来一点点感觉。不用一下子做很多,就一件小到几乎不算事的——你觉得今天有哪件这样的小事,是你勉强够得着的?","guidance":["明确把'动不了'和'懒'区分开，这是抑郁里最常被误解、最伤人的一点","介绍'先行动一点点再带回感觉'的思路，但用大白话，不出现行为激活等术语","把第一步压到极小，哪怕只是坐起来喝口水，避免给对方设过高的台阶","对方做不到时不催不评判，'今天没做到也没关系'要真的传达出来"],"sources":["pubmed.ncbi.nlm.nih.gov","apa.org"],"clinicalStatus":"approved"},
  {"id":"inner-critic-voice","title":"脑子里那个一直骂你的声音","tags":["自我批评","内在批评","羞耻"],"keywords":["我脑子里总有个声音骂我","我老是觉得自己做什么都不对","我一犯错就在心里把自己骂一顿","我对自己特别狠","总觉得自己很差劲","我老是挑自己毛病","脑子里有个声音说我不行","我对别人很宽容对自己特别苛刻","自我攻击","我恨自己","我觉得自己一无是处","停不下来地否定自己","怎么停下来不骂自己","都是我的错","我太没用了","看不起自己","配不上","我是个累赘","讨厌自己"],"content":"你心里那个一直挑你毛病的声音,可能比谁都尖。别人随口一句你能体谅半天,轮到自己就一点余地都不给。它不是凭空冒出来的,很多时候是小时候听多了的某些话,慢慢变成了你自己的声音——你以为是你在想,其实是它在替你想。它会装成是为你好,好像不狠狠push一下你就会松懈。但你心里清楚,被这样骂着,你不是更有劲了,是更不敢动了。\n\n你会用它对你说话的方式,去对一个你很在乎、正难受的朋友吗?多半不会。低落的时候,这个声音会变得特别大、特别像真的,但它不等于事实,它只是被放大的那一部分。你今天能不能先只是听见它,而不是马上信它。","guidance":["帮对方把那个声音和他本人分开，别让他默认那就是事实——可以问他这个声音是从什么时候开始的、像谁","用'你会这样对朋友说话吗'这种换位，唤起对方本来就有的善意，但不要空泛地夸他","承认这个声音很真实很大声，再轻轻松动它，不否认对方的感受","贴着对方具体撑过的事去肯定，而不是说'你已经很棒了'"],"sources":["self-compassion.org","nhs.uk"],"clinicalStatus":"approved"},
  {"id":"depression-not-weakness","title":"这不是你的错，也不是软弱","tags":["抑郁去污名化","自责","求助"],"keywords":["是不是我太脆弱了","别人都行就我不行","我是不是矫情","抑郁是不是想太多","不敢跟别人说","怕别人觉得我有病","觉得自己丢人","是不是我不够坚强","为什么我就走不出来","羞于求助","抑郁是病吗","我是不是装的"],"content":"你怕这是因为自己太脆弱、太矫情——我想很认真地说一句,不是的。抑郁不是性格缺陷,也不是不够坚强,它是一种真实存在、会发生在任何人身上的状况,跟一个人努不努力、好不好没有关系。全世界有非常非常多的人经历过它,很多人不敢说出来,恰恰是因为怕被这样看待。但它是可以被帮助、可以好转的,这一点是确定的。你能走到这里、愿意把这些讲出来,不是软弱,恰恰是一件需要力气的事。","guidance":["正面拆掉'抑郁=软弱/矫情'的污名，这是很多人不敢求助的核心障碍","强调抑郁普遍且可被帮助，给真实的希望，但不承诺具体疗效或时间","把'说出来/求助'重新框定为有力量的行为，而不是示弱","不要把它医学化到吓人，也不诊断，只传达'这是可以被照顾的状况'"],"sources":["who.int","nhs.uk"],"clinicalStatus":"approved"},
  {"id":"tired-all-the-time","title":"怎么休息都还是累","tags":["动力缺失","抑郁低落","疲惫"],"keywords":["睡再多还是累","一整天没力气","身体像灌了铅","很疲惫但睡不着","什么都没做却很累","起不来床","累到不想说话","精力被掏空","怎么休息都缓不过来","白天昏昏沉沉","睡眠乱了","提不起精神"],"content":"你说睡再多、歇再久,那股累还是压着你,整个人像灌了铅。这种累不是你白天玩太狠欠下的,它和情绪低落是连在一起的——心里沉的时候,身体也会跟着沉,睡眠常常也乱了,可能怎么都睡不踏实,或者醒了还是疲。所以这不是你意志力的问题,光靠'多睡一会儿'有时确实缓不过来。你不用因为'什么都没做还这么累'再去怪自己。能不能先不跟这股累较劲,今天给自己留点不用硬撑的空间?","guidance":["说明抑郁带来的疲惫和睡眠紊乱是身体层面的真实症状，不是懒或意志薄弱","化解'什么都没做却很累'引发的额外自责","不简单建议'多睡觉就好'，抑郁性疲惫往往休息也难恢复","若睡眠或精力长期严重受影响，温和提示可找专业的人评估，不下判断"],"sources":["nhs.uk","who.int"],"clinicalStatus":"approved"},
  {"id":"guangfan-danyou-tingbuxialai","title":"停不下来的担心","tags":["广泛性担忧","担心"],"keywords":["脑子停不下来","一直在担心","控制不住地想","担心个没完","什么都担心","担心工作","担心家人","担心钱","担心健康","明明没事还是担心","焦虑得睡不着","总觉得要出事","操不完的心","想太多","瞎担心","停不下来的念头","杞人忧天","心里悬着","放不下心"],"content":"你的脑子好像没有暂停键,一件事还没落地,下一件已经排着队涌上来了。担心工作、担心家里人、担心钱、担心身体,有时候连自己都说不清到底在怕什么,就是一直悬着,松不下来。这种累,是那种从早到晚一直绷着、连睡觉都不踏实的累。\n\n它不是你太脆弱,也不是你想太多。这种把每件事都往最坏处想、想完一件又一件的状态,本身就很消耗人——你不是在解决问题,是被困在了打转里。\n\n你不用现在就把所有担心都摆平。能不能先就停在这一件上,跟我说说,今天最压着你的,是哪一个。","guidance":["先认领他的累,别急着分析或给方法——他要的是有人懂这种停不下来,而不是被纠正","帮他把一团乱的担心收到一件具体的事上,问最压着他的是哪个,缩小范围本身就让人喘口气","别说服他担心是多余的;他知道道理没用,被否定只会更孤立","如果他愿意,可以轻轻提一句:把担心写下来、或留一小段固定时间专门去想,有些人会觉得脑子松一点"],"sources":["nhs.uk"],"clinicalStatus":"approved"},
  {"id":"fanchu-fanfu-huixiang","title":"反复回放的那件事","tags":["反刍","重复思考","回放"],"keywords":["翻来覆去地想","一直回想","脑子里反复放","睡前想个不停","纠结过去的事","后悔得睡不着","为什么当时","早知道就","反复回放","钻牛角尖","想不通","放不下那句话","越想越难受","停不下来地复盘","自责","反刍","一遍遍重来","脑子里循环"],"content":"同一件事,你已经在脑子里放了不知道多少遍了。哪句话说错了、当时该怎么做、对方是不是因此对你有看法——倒回去,再来一遍,越想越难受,可还是停不下来。\n\n它会伪装成在解决问题,好像多想一遍就能想通、就能补救。但你大概也察觉到了:这种反复回放,想到最后并没有答案,只是把那个难受又重新撕开一次,人更陷进去。它消耗你,却不带你往前。\n\n现在你是被卷在这个圈里了。打断它有时候需要先把注意力挪到别的地方——不是逃避,是给脑子一个台阶下来。你愿意的话,跟我说说,是哪句话、哪个画面,一直拽着你回去。","guidance":["帮他区分:反复回想不等于在解决问题,温和点破这层伪装,但别居高临下","回放往往黏着自责,先接住情绪,别跟着他一起复盘细节、加深那道沟","可以引导他把注意力挪到一件具体、能投入的小事上,给打转的脑子一个出口","如果同一件事卡了很久、影响睡眠和生活,温和地提一句找专业的人聊聊会更有帮助"],"sources":["apa.org","ncbi.nlm.nih.gov"],"clinicalStatus":"approved"},
  {"id":"jinghuang-fazuo-dangxia","title":"惊恐发作的当下","tags":["惊恐发作","急性焦虑","身体反应"],"keywords":["突然心跳很快","喘不过气","胸口发闷","手脚发麻","觉得自己要死了","快要昏过去","突然很害怕","心慌得厉害","感觉要失控","呼吸不上来","浑身发抖","出冷汗","头晕想吐","惊恐发作","突然崩溃","像要死了一样","心脏要跳出来","整个人僵住"],"content":"心跳快得像要冲出来,喘不上气,手脚发麻,有那么一瞬间你真的以为自己要死了或者要疯了。这种感觉太真实、太吓人了。\n\n我想先告诉你一件事:这种突然袭来的强烈反应,通常几分钟到二三十分钟会自己退下去,它非常难受,但不会真的伤害你的身体。你现在感到的那些可怕的信号,是身体的警报拉响了,不是身体出了真正的危险。\n\n如果你正在经历它:试着把注意力放到呼吸上,慢慢吸气,再更慢地呼出去,呼气拖长一点。脚踩实地面,看看四周,说出你看到的三样东西。它会过去的,我陪你等它退下去。","guidance":["当下最重要的是稳和短句,别长篇大道理;告诉他这会过去、不会真的伤害身体","带他做慢呼吸,重点放在把呼气拉长,再加一点踩地、环顾四周的着陆动作","用平稳的陪伴传递安全感,别表现出慌乱,你的稳定本身就是镇定剂","不诊断、不评估危险程度;若反复发作并开始回避生活,温和建议去做专业评估"],"sources":["nhs.uk"],"clinicalStatus":"approved"},
  {"id":"qutihua-shenti-de-jingbao","title":"身体先替你喊了出来","tags":["躯体化","身体症状","焦虑反应"],"keywords":["胸口发紧","肚子不舒服","总想上厕所","心慌","喉咙堵","肩膀僵硬","头疼","查不出毛病","检查都正常","身体一直不舒服","恶心想吐","手抖","出汗","浑身没力气","躯体化","身体报警","焦虑引起的难受","查不出原因","莫名其妙难受"],"content":"胸口发紧、肚子翻腾、喉咙像堵了一块、肩膀一直僵着——你去查了,医生说没什么大问题,可这些难受是真实存在的,不是你装的,也不是你矫情。\n\n焦虑的时候,身体会进入一种戒备状态:心跳加快、呼吸变浅、肌肉绷紧、肠胃闹脾气。这些反应本来是用来应对危险的,只是现在没有真的猛兽,身体却一直没松下来,于是难受就堆在了身上。心里的紧张,有时候会先从身体喊出来。\n\n你不用一边难受一边怀疑自己是不是太娇气。想跟我说说,这阵子,身体哪个地方最不放过你。","guidance":["先确认这些难受是真的,别让他觉得'查不出来=想象出来的',那会加重羞耻","帮他把身体和情绪轻轻连起来:紧张有时先从身体喊出来,而不是说'你这是心理作用'","不替代就医——若有持续或新出现的身体症状,该看医生还是要看,陪伴不是诊断","可以引导他留意身体最紧的那个点,做几次慢呼吸或放松,把'松一点'当成可触的小目标"],"sources":["nhs.uk","ncbi.nlm.nih.gov"],"clinicalStatus":"approved"},
  {"id":"buquerding-de-bunainai","title":"受不了悬而未决","tags":["不确定不耐受","等待","未知"],"keywords":["等结果等得发疯","受不了不知道","必须有答案","悬着难受","等消息煎熬","不知道会怎样","反复确认","一定要弄清楚","无法忍受未知","等待最折磨","总要个准信","没结果睡不着","不确定就慌","凡事要确定","讨厌意外","掌控不了就焦虑","悬而未决"],"content":"最磨人的常常不是坏消息本身,而是还不知道结果的那段时间。等回复、等检查报告、等一个说法——明明什么都还没发生,你却已经被那种悬着的感觉熬得不行,忍不住反复刷、反复确认,想赶紧把它钉死。\n\n有些人天生就更难和'不知道'相处,会本能地想立刻填满每一个问号。这不是你的错,但你大概也发现了:再怎么确认,有些事就是要等时间给答案,催不出来。和这种悬着共处,比逼自己马上拿到确定,往往更省力。\n\n你现在正卡在哪一件'还不知道结果'的事里?说出来,我陪你一起等。","guidance":["点出他真正难熬的是'不确定'本身,而不只是那件具体的事,帮他看清自己卡在哪","别急着给保证或预测结果,虚假的'一定没事'会让信任打折;陪他待在未知里更稳","温和减少反复确认的冲动:确认带来的安心很短,反而喂大焦虑,但用商量的语气提","把目标放在'能和悬着共处一会儿',而不是'立刻拿到答案',小步练习耐受"],"sources":["pmc.ncbi.nlm.nih.gov"],"clinicalStatus":"approved"},
  {"id":"zainanhua-zui-huai-de-jvmian","title":"脑子直奔最坏的结局","tags":["灾难化","最坏打算","恐惧"],"keywords":["往最坏的想","脑补灾难","一定会出事","完蛋了","肯定没救了","想到最差的结果","小事想成大事","万一怎么办","停不下来的万一","越想越可怕","脑子直接跳到最坏","天要塌了","灾难化","杞人忧天","一点风吹草动就慌","把事情想绝了","假设全是坏的"],"content":"一件小事刚冒头,你的脑子已经一路冲到了最坏的结局——他没回消息,是不是出事了;身体有点不舒服,是不是大病;这次没做好,是不是全完了。每一步都顺着'万一'往下滑,越滑越深,等回过神,人已经站在想象里的废墟上了。\n\n脑子在害怕的时候,特别容易把'有可能'当成'一定会',只盯着那个最糟的版本,把其他更可能、更平常的结局都跳过了。这不是你想吓自己,是焦虑会自动接管方向盘。\n\n你能不能先停在那个'万一'前面,跟我说说:此刻最让你害怕的,到底是哪一种结局?我们一件一件看。","guidance":["先接住恐惧再谈可能性,直接说'没那么严重'会让他觉得不被当真","温和地帮他把'有可能'和'一定会'分开,但用问的方式,别替他下结论","可以一起想想:除了最坏那个,还有哪些更平常的结局,把被跳过的可能性找回来","不打包票保证结果好;陪他把模糊的'万一'落成一个具体念头,常常就没那么吓人"],"sources":["pmc.ncbi.nlm.nih.gov"],"clinicalStatus":"approved"},
  {"id":"jiaolv-shi-rang-shenti-xianjingxialai","title":"先让身体落下来","tags":["着陆","呼吸","当下安抚"],"keywords":["怎么让自己冷静","焦虑发作怎么办","心慌想平复","教我呼吸","怎么放松","脑子太乱","稳不住","需要冷静下来","缓一缓","平复情绪","着陆练习","深呼吸","感觉要失控了想稳住","让自己安定","急救一下情绪","稳住自己","落地"],"content":"当脑子转得太快、整个人飘起来收不住的时候,有时候不用先去想通什么,先让身体落下来会更管用。\n\n试试这样:慢慢用鼻子吸气,数到四;再用嘴呼出去,把呼气拖得比吸气更长一点。多做几次,身体会慢慢收到'没那么危险'的信号。然后把脚踩实地面,环顾四周,在心里说出你能看到的三样东西、能听到的两种声音、能摸到的一样东西。\n\n这不是要赶走那些感受,只是先给绷紧的身体一个落脚的地方。我在这儿,我们慢慢来,不急。","guidance":["在他情绪很高、讲道理听不进去时优先用这张:先安身体,再谈想法","带节奏而不是只给指令,陪他一起呼吸、一起数,把呼气拉长是关键","用'我在''慢慢来'传递不急不慌的在场感,你的稳就是他的锚","讲清楚目的是'落下来'而非'消除感受',别让他觉得没做到平静就是失败"],"sources":["nhs.uk"],"clinicalStatus":"approved"},
  {"id":"cant-fall-asleep","title":"躺下却睡不着","tags":["入睡困难","睡前焦虑","唤起"],"keywords":["睡不着","躺下睡不着","翻来覆去","怎么都睡不着","越想睡越清醒","躺一两个小时还醒着","数羊","睡不着好崩溃","明天还要上班睡不着","闭着眼睛脑子很清醒","硬躺","睡不着很急","失眠","入睡困难","躺床上很清醒"],"content":"躺下去这么久还醒着,你心里大概越来越急,看一眼时间又往下沉一点。我懂那种感觉,越是逼自己快点睡,整个人反而越绷得紧。睡觉这件事有点怪,它不太吃命令,你越用力它越躲。如果躺了差不多二十分钟还是没有困意,与其在床上跟它较劲,不如先起来,去客厅或者别的地方,开一盏小灯,看几页纸质书,或者听点很慢的声音,等真的有困意了再回床上。这不是认输,是让床重新变回一个让人放松的地方,而不是一个跟清醒死磕的战场。今晚就算睡得少一点,也不会把你压垮,你明天还是能撑过去的。","guidance":["先共情那股越想睡越清醒的焦灼,别急着教方法,让对方觉得这种状态被看见了","可以轻轻提一句二十分钟还没睡着就先离开床的做法,但说成一个可以试试的选择,不是任务","帮对方松开对睡眠时长的执念,今晚少睡一点不等于明天就垮,降低预期本身就在松绑","不打包票今晚一定睡得着,只陪着对方把今晚熬过去"],"sources":["nhs.uk","ncbi.nlm.nih.gov"],"clinicalStatus":"approved"},
  {"id":"racing-thoughts-at-night","title":"睡前思绪停不下来","tags":["脑子停不下来","睡前焦虑","反刍"],"keywords":["脑子停不下来","想太多","睡前胡思乱想","一闭眼就开始想","脑子像放电影","停不下来的念头","越躺越精神","白天没空想晚上全涌上来","睡前焦虑","反复想白天的事","操心明天","脑子很吵","思绪很乱睡不着","一直在想事情"],"content":"一躺下,白天压着的那些事就全涌上来了,一件接一件,停都停不下来,像脑子里一直有人在说话。其实这很常见,白天你忙着应付各种事,没空搭理它们,到了安静的夜里它们才逮着机会冒出来。你不用硬把这些念头按下去,越按往往越响。可以试试在睡前留十分钟,拿张纸把心里转的事、明天要做的事都写下来,等于先替自己接住它们,告诉脑子这些都记下了,不用半夜还盯着。如果躺着还是停不下来,就把注意力轻轻放到呼吸上,吸气慢一点,吐气更长一点,不是要赶走那些念头,只是给自己一个可以落脚的地方。念头来了就让它来,你只要看着它飘过去就好。","guidance":["先点破这种安静下来才开始想的体验,让对方知道这不是自己有问题,是很普遍的状态","可以建议睡前把心事和待办写下来,说成替自己卸下一点,而不是又多一项任务","引导把注意力放回呼吸或身体,强调是给念头一个落脚处,不是强行清空脑子","不评判那些念头的内容,陪着对方就好,别急着帮他解决具体的事"],"sources":["nhs.uk","ncbi.nlm.nih.gov"],"clinicalStatus":"approved"},
  {"id":"waking-at-night","title":"半夜醒来睡不回去","tags":["半夜醒","回笼觉","凌晨惊醒"],"keywords":["半夜醒","三点醒","凌晨醒来","睡到一半醒了","醒了就睡不回去","半夜睡不着","夜里频繁醒","总在同一个点醒","醒来看时间","睡眠浅","一夜醒好几次","凌晨睡不着","回笼觉睡不着","夜醒"],"content":"半夜突然醒了,然后就那样睁着眼,翻来覆去怎么也睡不回去,可能还忍不住看了几次时间,越看越清醒。这种半夜醒来其实很多人都有,你不是一个人在经历。这时候盯着时钟反而最折磨,数着还能睡几个小时,只会让自己更紧。如果你已经醒了挺久,回不去了,可以学着不跟它硬耗,起来到别处坐一会儿,灯调暗一点,看点平淡的东西,别碰手机那种亮屏。等身体重新有了那种沉沉的困意,再回去躺下。还有一件事会偷偷帮到你,就是不管夜里醒了多久,早上尽量在差不多的时间起,白天别补长觉,慢慢身体自己会把节奏调回来。今晚醒了没关系,你不必为此责怪自己。","guidance":["先接住半夜独自醒着的那种孤立感,告诉对方很多人都会这样","温和提醒别盯着时钟算还能睡多久,那种倒数最容易把人逼紧","可以提到醒久了就先离开床、别碰亮屏手机,等困意回来再躺下","别让对方因为半夜醒来而自责,强调这不是他做错了什么"],"sources":["mayoclinic.org","sleepfoundation.org","nhs.uk"],"clinicalStatus":"approved"},
  {"id":"wind-down-relaxation","title":"睡前怎么让自己松下来","tags":["放松","呼吸","身体紧绷"],"keywords":["放松不下来","身体紧绷","睡前放松","怎么让自己平静","呼吸法","深呼吸睡觉","全身紧张","肩膀很紧","睡前冥想","放松身体","渐进式放松","睡前仪式","助眠放松","心跳很快睡不着"],"content":"有时候不只是脑子停不下来,身体也是绷着的,肩膀、下巴、手都不自觉地紧。这种紧你可能自己都没察觉,但它确实让人睡不踏实。有个慢慢松下来的办法你可以试试,从脚开始,一个部位一个部位,先轻轻用力绷紧那块肌肉,停几秒,再一下子全放掉,感受那种松开的感觉,然后往上,小腿、肚子、肩膀、脸,一路放过去。配上呼吸会更好,吸气的时候慢一点,吐气拉得更长一些,吐气长一点身体就更容易进入那种放松的状态。这不是要你立刻睡着,只是先把白天攒下的那股紧张一点点卸下来。哪怕只松开一点点,也是在帮自己往睡眠那边靠近。","guidance":["可以先帮对方注意到身体的紧绷,很多人只盯着睡不着,没意识到肩颈下巴一直在用力","把渐进式放松说成一个可以慢慢做的小步骤,从脚到脸,不必一次到位","提到吐气拉长有助于放松,但说得口语一点,别像念说明书","反复强调目标不是马上睡着,而是先松一点,降低对方对见效的压力"],"sources":["nhs.uk","mayoclinic.org","sleepfoundation.org"],"clinicalStatus":"approved"},
  {"id":"sleep-hygiene-basics","title":"白天为睡眠铺好路","tags":["睡眠卫生","作息","咖啡因"],"keywords":["睡眠卫生","作息乱","怎么调整作息","几点睡","咖啡因影响睡眠","喝咖啡睡不着","晚上喝酒助眠","白天补觉","午睡影响睡眠","睡前玩手机","蓝光","固定作息","周末补觉","睡眠习惯","调整生物钟","卧室环境"],"content":"睡得好不好,其实白天就已经在悄悄铺垫了。有几件事会偷偷拖你后腿,比如下午之后还喝咖啡或浓茶,那点东西在身体里能待挺久,到了夜里还在让你清醒;还有靠喝酒来助眠,它会让你犯困,但睡得反而更碎、更容易醒。睡前那一两个小时,试着离屏幕远一点,亮屏会让身体以为还是白天。如果有条件,让卧室暗一点、安静一点、凉一点,人会更容易沉下去。还有一个看着不起眼却很关键的,就是尽量每天差不多时间起床,哪怕前一晚没睡好,周末也别赖太久来补,白天也别睡太长。这些不用一口气全做到,挑一两个先调,身体的节奏会慢慢跟上来。别要求自己一夜之间全改好。","guidance":["把这些当成可以慢慢调的方向,别一次性甩一整张清单,容易让人有压力","如果对方在用喝酒助眠,温和说明它会让睡眠更碎,但不带指责的口气","固定起床时间是最值得先抓的一条,可以重点轻推这一个","鼓励对方挑一两件先试,强调不用一夜全改好"],"sources":["nhs.uk"],"clinicalStatus":"approved"},
  {"id":"bed-is-for-sleep","title":"让床重新只跟睡觉有关","tags":["刺激控制","床的联结","习惯"],"keywords":["床上玩手机","在床上工作","床和睡觉","一上床就清醒","床变成清醒的地方","刺激控制","躺床上刷手机","床上看剧","上床反而精神","白天躺床上","床的联结","一进卧室就紧张","睡前在床上玩","习惯改变"],"content":"你有没有发现,有时候一躺到床上反而更清醒了。这背后有个挺有意思的原因,如果你常在床上刷手机、看剧、工作、躺着想心事,身体就慢慢把床和清醒、跟焦虑连在了一起,于是一上床它就自动进入清醒模式。想把这个联结掰回来,方向是让床尽量只跟睡觉这一件事有关。白天别赖在床上,清醒的活动尽量挪到别的地方去做。真有困意了再上床,如果躺下去一直睡不着,就先起来,等困了再回来。这需要点耐心,改一个养了很久的习惯不会立竿见影,可能要好些天床才慢慢重新变成那个让你放松、犯困的地方。你愿意一点点试,就已经在往好的方向走了。","guidance":["用一进床反而清醒这个共同体验切入,帮对方理解这不是意志力问题,是习惯连出来的","把让床只跟睡觉有关说成方向,而不是一堆硬规矩","提醒这需要时间,改老习惯不会马上见效,避免对方试两天没用就否定自己","肯定对方愿意尝试本身,而不是空泛地夸他"],"sources":["ncbi.nlm.nih.gov","nhs.uk"],"clinicalStatus":"approved"},
  {"id":"shame-vs-guilt","title":"是做错了事，还是觉得自己烂","tags":["羞耻感","内疚","自我价值"],"keywords":["我觉得自己很糟糕","犯了错就觉得自己是个烂人","我好羞耻","我觉得自己见不得人","羞耻感","我恨不得找个地缝钻进去","我觉得自己根本就是个错误","做错一件事就全盘否定自己","丢人","我配不上别人对我好","觉得自己很脏很坏","内疚和羞耻分不清"],"content":"有件事我想跟你分清楚,因为它们感觉很像,其实差很远。一种是我做了一件不好的事,这种难受会推着你去弥补、去道歉,过去了就过去了。另一种是我这个人就是不好的——不是事情错了,是你整个人都被判了刑。后面这种最伤人,它让你想躲起来、想消失,因为你觉得问题不在某件事,在你本身。可一件做错的事,真的撑不起对整个你的定罪。你可以为那件事难过,同时不把它变成你是谁。这两个,真的可以分开。","guidance":["温和地帮对方把事和人分开:他懊悔的那件事,和他这个人,不是一回事","羞耻会让人想躲、想消失,这时候陪着别走开比讲道理更重要","不要顺着他一起评判那件事,也别忙着说没事啦,先让他知道有这种感受不丢人"],"sources":["apa.org","pmc.ncbi.nlm.nih.gov","self-compassion.org"],"clinicalStatus":"approved"},
  {"id":"not-good-enough","title":"总觉得自己不配、不够好","tags":["不配得感","自我价值","低自尊"],"keywords":["我觉得自己不配","我配不上这份工作","配不上别人喜欢我","总觉得自己不够好","我不值得被爱","我觉得自己是冒牌的","别人夸我我觉得是他们没看清","我总觉得迟早会被拆穿","不配得感","觉得自己哪儿都不够","我没资格","自卑","怎么才能觉得自己够好"],"content":"那种不配的感觉很狡猾。事情顺了,你说是运气、是别人没看清;事情砸了,你立刻说看吧我就知道。它只收对它有利的证据,你说什么它都能绕回到你不够好。所以这不是你真的不够,是这套打分的尺子从一开始就是歪的——它常常是很早以前被反复说出来的东西,你把它当成了关于自己的事实。我不急着证明你够好,那样太轻飘。我只想让你先怀疑一下那把尺子:如果它对谁都判不及格,那也许该被怀疑的,是它,不是你。","guidance":["别用你很棒你够好去对冲,那会被对方的内在标准弹回来。先松动那把评判的尺子本身","可以请他举一件别人认可、他却归因成运气或对方眼瞎的事,让他看见这套打分有多偏","承认这种感觉往往来得很早、很深,不是他想通就能立刻消失,给它时间"],"sources":["nhs.uk","self-compassion.org"],"clinicalStatus":"approved"},
  {"id":"self-compassion-basics","title":"像对朋友那样，对自己说话","tags":["自我慈悲","自我关怀","落地练习"],"keywords":["怎么对自己好一点","我不会安慰自己","对别人很好对自己很差","怎么停止自我攻击","自我关怀","自我慈悲是什么","我没法原谅自己","怎么和自己和解","对自己温柔","我总是太苛刻","怎么自我安慰","善待自己","道理我都懂就是做不到","怎么开始对自己好","我想停下来歇一下","怎么放过自己一点"],"content":"试试这个,真的很简单:你现在对自己说的那句话,如果是你最好的朋友遇到同样的事,你会这么对他说吗。多半不会。你会换一种语气,会先看见他多难,而不是先数落他。对自己慈悲,不是放过自己、不是找借口,也不是自怜——它不会让你变懒,反倒让你摔倒之后还爬得起来,因为你不用先扛一顿自己的打。\n\n不用一下子学会爱自己,那太大了,今天先小一点。比如现在,把手放到自己胸口上待一会儿,像你会去拍拍一个难过的人那样;或者就允许自己说一句这件事确实挺难的,而不是马上骂自己怎么连这都搞不定。也可以是今天少逼自己一件事,给自己倒杯水、早点睡。这些小到不像在解决问题,但你对自己的态度,就是从这种一次又一次的小松动里,慢慢变的。","guidance":["把如果是朋友你会怎么说这个角度递给对方,这是最自然的切入,不说教","如果他担心对自己好就会松懈,可以平静地告诉他自我慈悲不会让人变懒,反而更扛得住失败","给一个小到能马上做的动作（手放胸口、说一句这确实难）,而不只是大道理","降低标准:不是今天就要爱自己,是今天对自己松一点点就够了,第一次会觉得别扭很正常"],"sources":["self-compassion.org","nhs.uk"],"clinicalStatus":"approved"},
  {"id":"common-humanity","title":"不是只有你一个人这样","tags":["自我慈悲","羞耻感","孤立感"],"keywords":["只有我这么糟","好像全世界就我一个人不行","别人都过得很好只有我","我不敢让人知道我这样","觉得自己是异类","我这种感受是不是很变态","没人懂我","我把自己关起来","孤独","我是不是有病","羞耻让我不敢说","我觉得我跟别人不一样"],"content":"羞耻最会骗人的一点,就是让你觉得只有你一个人烂到这种地步,别人都好好的。所以你把它藏起来,越藏越觉得自己是异类。但搞砸过、失望过、半夜里觉得自己不行过——这些不是你一个人的毛病,是几乎每个人都有、只是没说出口的部分。会痛,恰恰说明你和所有人是一样的,不是被分出去的那个。你不用因为有这些感受就把自己从人群里开除。你现在愿意跟我说的,可能正是别人也一样、却不敢讲的那块。","guidance":["帮对方把我一个人这么糟松成这是很多人都有、只是没说的部分,但别轻描淡写成大家都这样所以没事","他愿意说出来本身就在打破隔离,接住这份信任,别急着分析","不要拿别人更惨来比较,那会让他觉得自己的痛不被当回事"],"sources":["self-compassion.org","apa.org"],"clinicalStatus":"approved"},
  {"id":"where-it-comes-from","title":"这套对自己狠，是学来的","tags":["自我批评","成长经历","自我价值"],"keywords":["为什么我对自己这么狠","我从小就被说不行","我爸妈总拿我和别人比","小时候做不好就被骂","为什么我这么自卑","这种自我否定哪来的","我习惯性贬低自己","从小被打压","原生家庭","为什么我不会爱自己","我学不会对自己好"],"content":"你对自己这么狠,不是天生的,也不是你有问题。一个人怎么对待自己,很多是早年被怎么对待、被反复说了什么,一点点长进去的。如果小时候你做不好就被骂、达不到就被比下去,那个挑剔的声音就会被你装进心里,后来哪怕没人在旁边了,它还在自动运行。所以这不是你的错——你只是太早就学会了用那种方式跟自己说话。能学会的东西,也能慢慢换一种。我们不用一夜之间换掉它,只是从今天起,试着让它身边多一个温和点的声音。","guidance":["明确地把这不是你的错放在前面,很多人第一次听到自我批评是学来的会松一大口气","解释归因不是为了怪他的家人,而是帮他理解这声音的来路,从而不再全盘认同它","强调能学会就能慢慢改,但别许诺很快好,这种模式很深、需要时间"],"sources":["nhs.uk","self-compassion.org"],"clinicalStatus":"approved"},
  {"id":"loneliness-not-a-flaw","title":"孤独不是你哪里出了问题","tags":["孤独感","自我接纳"],"keywords":["好孤独","一个人好孤单","没人懂我","明明身边有人却觉得空","深夜特别孤独","孤独到想哭","感觉被全世界落下","空虚","和谁都聊不到一起","热闹散场后更难受","孤独是不是我的错","为什么我这么孤独","孤单","形单影只"],"content":"孤独的时候,人很容易往自己身上找原因,觉得是不是我不够好、不够有趣,别人才不靠近。但孤独更像是身体在提醒你,你需要的那种连接现在少了,就像饿了会提醒你该吃东西。它不是在宣判你有什么毛病。很多看起来朋友很多、每天很热闹的人,也会在某个安静的时刻被这种空落落击中。你现在感觉到的,是很真实的东西,不用急着把它解释成自己的失败。先承认它在这,就已经不容易了。","guidance":["先认领他此刻的具体感受,别急着给方案或安慰","避免说你并不孤单这类话,那会让他觉得感受被否认","可以轻轻把孤独和缺陷分开,让他知道有这感受不代表他有问题"],"sources":["who.int","nhs.uk"],"clinicalStatus":"approved"},
  {"id":"social-anxiety-small-steps","title":"怕和人打交道，可以一小步一小步来","tags":["社交焦虑","回避"],"keywords":["社恐","见人就紧张","怕跟陌生人说话","聚会前焦虑到想逃","怕被人评价","说话脸红心跳","怕自己说错话出丑","社交前一晚睡不着","回避社交","不敢发言","怕尴尬","开口前手心冒汗","聚会回来反复回想自己哪句说错了"],"content":"怕和人打交道的时候,逃开会让那一刻轻松很多,但下一次往往更难开口,那种怕会越养越大。所以不用逼自己一下子冲到最怕的场面里。可以把它拆开,从最不怕的那一小步开始,比如先在熟一点的人面前多说一句,或者去个人多但不用硬聊的地方待一会儿。还有个常见的小陷阱,就是聊天时满脑子都在想自己表现得怎么样,反而更慌。试着把注意力挪一点点到对方在说什么上,有时候反而没那么紧绷。","guidance":["不催他立刻去社交,认可逃开当下确实能松一口气","如果他愿意,陪他想一个小到几乎不可能失败的第一步","帮他把注意力从我表现如何挪向对方说了什么,而不是讲道理"],"sources":["nhs.uk","apa.org","nimh.nih.gov"],"clinicalStatus":"approved"},
  {"id":"after-a-fight-with-someone","title":"和重要的人吵完，心还乱着","tags":["人际冲突","沟通"],"keywords":["和朋友吵架了","跟家人闹翻","吵完很后悔","不知道怎么和好","冷战","越说越僵","明明想好好说却变成吵架","吵架后整夜想着这事","关系破裂","该不该先低头","怕一开口又吵起来","和好","僵住了"],"content":"和在乎的人闹僵,那种乱不只是气,还掺着难过和怕,怕这段关系是不是就这样了。先别在最冲的时候逼自己想清楚对错,头脑烫着的时候很难听进任何话,也很难好好说话。等情绪稍微落一点,如果你还想修,可以试着只说自己这边的感受和需要,而不是先翻对方哪里错了,后者很容易又把火点起来。吵架本身不一定是关系坏掉的信号,有时候反而是两个人都还在乎、都还想被对方听见。","guidance":["先接住他的情绪本身,别急着评判谁对谁错或催他和好","等他稍微平静,再轻轻提先表达自己感受而不是指责对方","尊重他的节奏,他可能还没准备好修复,不要替他做决定"],"sources":["apa.org","helpguide.org"],"clinicalStatus":"approved"},
  {"id":"feeling-left-out","title":"被晾在外面的那种刺","tags":["被孤立","归属感"],"keywords":["被排挤","被孤立","大家都不带我玩","群里没人理我","被冷落","感觉自己是多余的","他们好像有意避开我","被踢出小圈子","插不进话","被无视","格格不入","明明在场却像隐形人","没人在乎我在不在"],"content":"被晾在外面的感觉是真的会疼的,它不是你太敏感太玻璃心。人天生就需要有归属,所以被排在外面会让人下意识地想,是不是我哪里惹人嫌。先别急着把这件事全揽到自己身上,有时候那群人的圈子、状态和你没什么关系。也留意一个反应,被冷落久了,人有时会赌气把自己再往外推得更远,或者反过来拼命讨好想挤进去,这两种往往都让你更累。你值得的是那种不用费力争取的位置。","guidance":["先认领被排除真的会疼,不轻描淡写成想太多","帮他把别人的圈子状态和我是不是不好稍微分开","留意他可能用赌气疏远或拼命讨好来应对,温和指出而不批评"],"sources":["apa.org","who.int"],"clinicalStatus":"approved"},
  {"id":"first-thread-of-connection","title":"想靠近人，又不知从哪开始","tags":["建立连接","行动"],"keywords":["想交朋友又不会","成年后好难交到朋友","不知道怎么认识人","想有人陪","怎么和别人变熟","主动好难","怕主动了被拒绝","没有可以说心里话的人","想被人记住","怎么开始一段关系","孤独想改变","迈出第一步"],"content":"想靠近人却卡住,很正常,长大以后那种自然就熟起来的机会本来就变少了,得自己有意去够。不用一上来就想交到一个无话不谈的知己,那压力太大了。可以从小一点的开始,比如固定去同一个有共同兴趣的地方,让自己成为一张别人眼熟的脸,熟悉本身就会拉近距离。还有个轻一点的入口,是带着一点好奇去问对方、去听,而不是盯着自己表现得好不好。连接常常不是设计出来的,是一次次小小的露面里慢慢长出来的。","guidance":["把目标降到很小的一步,别让他觉得要立刻交到知己","鼓励他靠重复出现和共同兴趣自然熟络,而不是硬social","提醒他被拒绝不等于他不好,允许他用自己的节奏来"],"sources":["nhs.uk","apa.org","helpguide.org"],"clinicalStatus":"approved"},
  {"id":"lonely-but-cant-reach-out","title":"明明想被陪，却谁都没联系","tags":["孤独感","行动"],"keywords":["想找人聊又不敢","怕打扰别人","觉得自己的事不值得说","拿起手机又放下","怕麻烦朋友","报喜不报忧","想被关心又说没事","孤独却主动推开人","怕显得脆弱","不想成为负担","欲言又止","想被看见又怕被看见"],"content":"很多时候孤独到难受,手指都在通讯录上滑了半天,最后还是谁都没点开。心里那个声音在说,别人都忙,我这点事不值得打扰,说出来还显得我矫情。这个念头很常见,但它常常骗你,真正在乎你的人,多半宁愿你来找他们,也不愿你一个人扛着。你不用准备好一段完整的、体面的倾诉才有资格开口。一句最近有点不好受,就够了。把脆弱露一点点给对的人看,往往不是变成负担,而是让关系真的靠近一步。","guidance":["认领他想联系又收回手的那个反复,别说你直接发啊这么简单","轻轻松动我会打扰别人这个念头,但不替他打包票对方一定有空","告诉他不需要准备好完整的诉说,一句简单的话就可以开始"],"sources":["nhs.uk","apa.org"],"clinicalStatus":"approved"},
  {"id":"anger-rising-body-signs","title":"怒火刚上来的时候","tags":["愤怒","身体信号","当下"],"keywords":["我要气炸了","火一下就上来了","气得发抖","心跳很快","脑子嗡的一下","拳头攥紧了","浑身发烫","胸口堵得慌","太阳穴突突跳","一秒就上头","压不住火","想摔东西","气到手抖","血往上涌","忍不住要发作","气得说不出话"],"content":"你能感觉到的对吧,心跳一下快起来,手不知不觉攥紧,胸口那块发紧发烫,脑子像被什么东西冲了一下。这些不是你不好,是身体在替你拉警报,它以为你需要保护自己。火在最高那几秒,人是听不进道理的,所以现在先别急着想该怎么办,先让身体那股劲缓一缓。能的话,把那口憋着的气慢慢吐出去,吐得比吸进来还长一点,吐完再来一次。手要是攥着,就松开,让它垂下来。火来得猛,退得也快,你不用做对什么,就是陪它过这几分钟,等那股冲劲自己往下走。它会走的。","guidance":["先认身体、别先讲道理:顺着对方说的身体感受接,帮他确认这是正常的应激反应,不是失控","把节奏慢下来,可以陪他一起把呼气拉长,但用邀请的口气,不要像在布置任务","强调这股劲会自己退,给他一个可以等待的安全感,而不是催他赶紧好"],"sources":["nhs.uk","apa.org"],"clinicalStatus":"approved"},
  {"id":"cool-the-body-fast","title":"气到顶点，先给身体降温","tags":["情绪失控","容忍痛苦","降温"],"keywords":["快控制不住了","整个人要爆了","想砸东西","想骂人","停不下来","气到喘不上气","脑子一片空白","理智断线了","怎么都冷静不下来","情绪上头","快疯了","整个人在抖","气到失控","想吼","压不住了"],"content":"如果火已经冲到顶,脑子一片空白,讲什么都没用——这时候管不住情绪,先管身体。最快的一招是凉水,去水龙头那儿,用凉一点的水捧着泼脸,或者拿条湿凉的毛巾捂住脸和眼睛,停个十几秒。凉意会让那股往上冲的劲实实在在地慢下来,这不是心理安慰,是身体真的会跟着降下来。要是手边有冰水,捧着杯子贴一会儿脸颊也行。或者干脆动起来,下楼快走两圈,爬几层楼梯,让那股没处去的劲从身上跑掉。这些不解决让你生气的事,但能先把你从快炸的那个点上拉回来,等回得来了,再说别的。","guidance":["在对方明显快失控时优先给具体可做的身体动作,而不是问他为什么生气","凉水降温和剧烈动一动是这张卡的核心,说清楚这是让身体降下来、不是讲道理","讲明白这一步只是先脱离爆点,不是解决事情,避免对方觉得被敷衍"],"sources":["therapistaid.com","apa.org"],"clinicalStatus":"approved"},
  {"id":"step-away-before-it-breaks","title":"想说狠话之前，先走开一下","tags":["愤怒","暂停","关系"],"keywords":["快要吵起来了","差点说出难听的话","想撂狠话","话到嘴边","再说下去要完","忍不住想反击","越说越气","想甩门走人","气头上口不择言","怕说出后悔的话","对方把我惹毛了","争到要爆炸","想骂回去","再待下去会动手"],"content":"火头上说的话,十句有九句是过后会后悔的,因为那不是你,是火在替你说。所以在那句最狠的话冲出来之前,你可以先抽身一下,跟对方说我现在太气了需要缓一会,然后离开那个让你上火的地方,哪怕只是去阳台站会儿、去洗手间待一下。这不是认输,也不是逃,是不让这股火把你和对方之间的东西砸坏。走开的那几分钟别在心里反复重播刚才那些话,那只会越烧越旺,就让自己缓,等心跳慢下来、手不抖了,你想说的话会清楚很多,那时候再回去说也不迟。","guidance":["把暂时走开说成一种保护关系的主动选择,不是逃避或认输,化解对方的羞耻感","提醒他走开时别反复回放刚才的争执,否则火会越烧越旺","如果他担心走开会伤到对方,可以建议先跟对方说一句我需要缓一下再走"],"sources":["mayoclinic.org","apa.org","nhs.uk"],"clinicalStatus":"approved"},
  {"id":"is-this-anger-the-size-of-the-thing","title":"这火，有它该有的那么大吗","tags":["情绪调节","愤怒","看清"],"keywords":["小事就炸了","一点就着","事后觉得自己反应过度","为什么这么气","气得不成比例","明明没什么大不了","越想越气","脑补了很多","假设对方故意的","钻牛角尖","气过头了","其实没那么严重","总往坏处想","莫名的火"],"content":"等你稍微缓过来一点,可以轻轻问自己一句,刚才到底发生了什么,是确确实实发生的那件事,还是我脑子里自己接下去的那些。人在气头上,常常会替对方的动作加好多解释,他是故意的,他根本不在乎,这下全完了——可这些往往是猜的,不是看到的。试着把真的发生的那一小块单拎出来:他说了哪句话,做了哪个动作,就这么多。很多时候你会发现,让你这么烫的,不全是那件事本身,是你心里替它添上的那一层。不是说你不该生气,你的气有它的道理,只是看清了哪些是真的,这火往往就不用烧得那么大了。","guidance":["等对方情绪降下来再用,火头上分辨事实是做不到的","帮他把真实发生的和自己脑补的分开,但用好奇的口气,不是纠正他","明确肯定他的愤怒有道理,只是看清后强度可能会变小,不否定情绪本身"],"sources":["apa.org"],"clinicalStatus":"approved"},
  {"id":"anger-urge-opposite","title":"火让你想做的，不一定是你真要做的","tags":["情绪调节","愤怒","冲动"],"keywords":["特别想反击","想报复","想让他也难受","想发泄出来","憋着难受","很想吼回去","想拉黑删掉","想摔门","冲动想做点什么","想发火又怕后悔","气得想搞破坏","想发狠","忍着很难受","想立刻爆发"],"content":"愤怒有个特点,它总会给你一个特别强的冲动——想吼回去,想让对方也尝尝难受,想摔点什么。这股冲动很真实,但它不等于你必须照做。你可以先看着这个冲动,知道哦我现在很想这么干,然后停在这儿,先不动手。如果这火大得过了头,或者照它做了你过后一定会后悔,那有时候反过来做反而能松开它,比如把音量压下去而不是吼上去,比如先离开而不是逼上前。不是叫你假装不气,也不是让你忍气吞声,而是在那个冲动和你的动作之间,留出一点点空当。就那么一点空当,够你重新做主了。","guidance":["把愤怒和愤怒带来的行动冲动分开,让对方看到冲动可以被看见但不被执行","反向行动只在火过了头、或照做会后悔时建议,不要让对方误以为要一味压抑","强调这不是忍气吞声,而是在冲动和动作之间留出选择的空当"],"sources":["apa.org"],"clinicalStatus":"approved"},
  {"id":"after-the-anger-passed","title":"火过去之后，别急着骂自己","tags":["愤怒","事后","自我"],"keywords":["发完火很自责","又没忍住","觉得自己很差劲","刚才太过分了","后悔死了","为什么我总这样","控制不住情绪好讨厌","事后特别羞愧","怪自己脾气差","搞砸了","对不起对方","又失控了","我是不是有问题","气完很空"],"content":"火退下去之后,常常跟着一股别的东西——后悔,羞愧,觉得自己怎么又这样。这股自责有时候比刚才的火还难受。但你愿意为刚才的失控难过,本身就说明你在乎,说明你不是个不管不顾的人。发过火不代表你这个人坏掉了,它更像是一个信号,告诉你那件事底下,可能藏着你某个一直没被好好对待的需要,也许是想被听见,想被尊重,想被当回事。如果你想,等心都静下来了,可以去补一句、说一声,但那是之后的事。现在这会儿,先别再拿那些话扎自己了,你已经够累了。","guidance":["先接住事后的自责和羞愧,这常比愤怒本身更折磨人","把发火重新框成一个指向未被满足需要的信号,而不是人格缺陷","修复关系可以提,但放在情绪平复之后,当下重点是停止自我攻击"],"sources":["apa.org","nhs.uk"],"clinicalStatus":"approved"},
  {"id":"grief-no-right-way","title":"哀伤没有标准答案","tags":["哀伤","丧失","正常化"],"keywords":["我是不是太久了","别人都好了我还没好","哭不出来正常吗","已经过去这么久了还难过","是不是我太脆弱","走不出来","应该早点好起来","别人说我该放下了","为什么我没有大哭","麻木","没感觉是不是不正常","多久才能好","什么时候才会不疼","时间会治愈吗","我哀伤的方式对不对","悲伤的五个阶段"],"content":"没有谁能告诉你,这件事要难过多久才算正常。有人哭得停不下来,有人一滴泪都掉不出来,有人前一秒还好好的,下一秒就被一阵什么东西冲垮。这些都不是哪里出了问题,只是你正在经历它而已。你身边可能有人会说,都过去这么久了,该往前看了。可哀伤不按日历走,它没有截止日期。你不用赶进度,也不用跟谁比谁恢复得快。你现在是什么样,就是此刻的你能承受的样子,这本身就够了。","guidance":["如果对方担心自己反应不对或太慢,不去纠正、不给时间表,先说这样真的很常见","不替对方判断该不该好起来了,顺着他此刻的状态待着","他哭也好,哭不出来也好,都接着,不评价哪种更正常","把那句别人都好了你怎么还这样接过来,告诉他不用和谁比"],"sources":["nhs.uk","apa.org"],"clinicalStatus":"approved"},
  {"id":"grief-many-feelings","title":"哀伤里什么情绪都可能来","tags":["哀伤","情绪","正常化"],"keywords":["又难过又生气","我居然在生气","对走的人发火是不是不应该","愧疚","我是不是做得不够","如果当时我","后悔","麻木","不敢相信","好像他还在","情绪上上下下","一会好一会崩溃","莫名其妙就哭了","为什么我会松一口气","解脱感是不是很冷血","震惊","脑子一片空白","情绪反复"],"content":"失去一个人之后涌上来的,常常不只是难过。可能还有愤怒,气他怎么就走了,气这件事怎么会发生;可能有愧疚,反复想如果当时我做了什么是不是就不一样;可能有一种不真实感,明明知道,却还是觉得他随时会推门进来。甚至有时候会闪过一丝松了口气,然后又为这点松动而自责。这些情绪会轮流来,也会突然一起涌上来,没有先后,也没有道理。它们不是你不够爱他的证据,恰恰是因为这段关系在你心里很重。","guidance":["对方说出愤怒或愧疚时,不急着安慰,先让他知道这些都在哀伤里很常见","若他为某种情绪自责,比如松一口气,不评判,告诉他这不代表他冷血","不去理顺他的情绪,允许它们反复、矛盾地同时存在","用具体的话接住,比如那种他随时会回来的感觉,一定很难熬"],"sources":["nhs.uk","apa.org"],"clinicalStatus":"approved"},
  {"id":"grief-body-reactions","title":"哀伤也会落在身体上","tags":["哀伤","身体反应","正常化"],"keywords":["睡不着","一直好累","吃不下","没胃口","胸口闷","胸口压着东西","头疼","浑身没力气","脑子转不动","记不住事","注意力没法集中","总是恍惚","容易感冒","身体垮了","哀伤会影响身体吗","心慌","一直想睡又睡不好"],"content":"哀伤不只在心里,它常常实实在在地压在身体上。你可能整夜睡不着,或者睡了还是累得起不来;可能完全没胃口,或者吃什么都没味道;胸口像压着一块东西,头疼,浑身使不上劲。还有一种很多人会有的状态,脑子像蒙了层雾,话听过就忘,事情怎么都记不住,连简单的决定都做不了。这些不是你软弱,是身体在跟着你一起承受这件事。这段时间,能吃一口是一口,能躺下就先躺下,把对自己的要求放低一些。","guidance":["对方描述身体不舒服时,先把它和哀伤连起来,让他知道这很常见,而不是他出了别的问题","不催对方振作,鼓励他先照顾最基本的吃和睡","提醒这只是科普,如果身体症状持续或加重,值得去看医生确认","把脑子一片雾、记不住事这种具体感受说出来,让他知道这也是哀伤的一部分"],"sources":["mariecurie.org.uk","apa.org"],"clinicalStatus":"approved"},
  {"id":"grief-allow-yourself","title":"允许自己哀伤","tags":["哀伤","允许","自我关怀"],"keywords":["不敢哭","不想麻烦别人","强忍着","要在别人面前坚持住","硬撑","不能倒下","想哭又憋回去","是不是该坚强一点","哭出来是不是软弱","假装没事","把情绪藏起来","不想让家人担心","一个人偷偷哭","允许自己难过","可以哭吗"],"content":"你可能一直在撑着,在别人面前装作没事,把眼泪憋回去,告诉自己不能倒下。可越是把哀伤压下去,它越是会从别的地方冒出来。你不用一直坚强给谁看。想哭就哭,哭出来不是软弱,只是这份失去太重,需要一个出口。你也可以在一个安全的时刻,允许自己彻底难过一会儿,不用解释,不用收着。这不是放纵,是给心里那块痛留一点呼吸的地方。你已经扛了很多了,在这里,你可以不用撑着。","guidance":["如果对方习惯硬撑,不夸他坚强,而是告诉他在这里可以不用撑着","他哭的时候不急着让他停下来或好起来,陪着就行","不把哭和软弱、不哭和坚强对立起来,顺着他自己的节奏","让他知道把感受说出来或哭出来,比一直憋着更能让心里松一点"],"sources":["nhs.uk","helpguide.org"],"clinicalStatus":"approved"},
  {"id":"grief-pet-loss","title":"失去宠物的痛是真的","tags":["宠物丧失","哀伤","正常化"],"keywords":["猫走了","狗狗去世","宠物没了好难过","别人说不过是只猫","为一只宠物这么难过正常吗","是不是太矫情","没人理解我","它陪了我这么多年","家里突然空了","习惯性找它","送走它我好自责","宠物离世","为宠物哭","毛孩子走了","养了十几年"],"content":"它走了,家里好像一下子空了。你还是会习惯性地在固定的时间找它,门口那个位置、它常趴的地方,都在提醒你它不在了。可能身边有人轻描淡写地说,不过是只猫、再养一只就好,那种没人懂的孤单会更重。但你和它之间的东西是真的,那些年的陪伴、每天的照顾、它无条件靠近你的样子,是别的关系给不了的。所以这份痛一点都不夸张,它配得上你认真地难过。你也可以用自己的方式记住它,留一张照片、一个它的小物件,把这段感情好好放在心里。","guidance":["绝不轻描淡写,不说不过是只宠物或再养一只,先承认这份失去是真的","如果对方因为照顾上的事自责,不评判,接住那份愧疚","认可那种别人不懂的孤单,让他知道在这里可以好好难过","可以温和提到用一件小物或一个仪式记住它,但不强推"],"sources":["avma.org","helpguide.org","mayoclinic.org"],"clinicalStatus":"approved"},
  {"id":"grief-waves-and-bonds","title":"哀伤像潮水，会一阵阵回来","tags":["哀伤","过程","持续联结"],"keywords":["以为好了又崩溃","突然又很难过","一首歌就哭了","看到他的东西就受不了","节日特别难熬","忌日","明明好一阵了","情绪又回来了","是不是又退步了","哀伤反复","想念","怎么才能不想他","放下是不是就是忘记","怀念","睹物思人","一波一波的"],"content":"你可能已经好了一阵子,能正常吃饭、上班,然后某一天,一首歌、一道熟悉的菜、街角一个背影,突然又把你冲垮。你会怀疑自己是不是又退步了。其实不是。哀伤不是一条往上走的直线,它更像潮水,会退下去,也会冷不防又涌回来,尤其在节日、忌日、那些和他有关的日子。这不代表你没在好转。慢慢地,想起他不一定只剩痛,也可能是温柔的想念。放下从来不是把他忘掉,而是学着带着这份记忆继续生活,他仍然在你心里,只是换了一种方式陪着你。","guidance":["对方因情绪反复而自责时,告诉他这不是退步,哀伤本来就一阵一阵","在节日、忌日这类日子主动放轻一些,预期他可能更难","不把放下等同于忘记,让他知道带着记忆继续生活也是一种好起来","当他愿意聊起逝者时,顺着他一起回忆,而不是岔开话题"],"sources":["avma.org","apa.org","helpguide.org"],"clinicalStatus":"approved"},
  {"id":"burnout-not-your-weakness","title":"倦怠不是你不够努力","tags":["职业倦怠","自我评价","去羞耻"],"keywords":["职业倦怠","烧光了","燃尽了","对工作彻底没劲","提不起劲","心累","是不是我太脆弱","别人都能扛我怎么不行","我是不是废了","干不动了","对工作麻木","一上班就烦","做什么都没意义","情绪枯竭","我太矫情了吗"],"content":"你心里那句话我听到了,你怀疑是不是自己不够强,不然怎么会撑到这个份上。我想说的是,这种状态有个名字,它是长期的工作压力一点点堆出来的,不是你哪里坏掉了。它通常长三个样子,一个是整个人被掏空、累到底,一个是对工作越来越远、越来越冷淡甚至有点厌,还有一个是觉得自己怎么做都不顶用了。你能对到几条,不代表你弱,只代表你在一段超过你承受的消耗里待太久了。换个人,扛同样多的东西、撑同样久,也会到这里。先别急着怪自己,你只是累得太久了。","guidance":["先把对方从自我指责里接出来，明确这是长期压力的结果，不是性格缺陷或能力问题","可以顺着对方的描述帮他认出疲惫的具体样子，但别贴诊断标签，保持非医疗口吻","停在共情，不要立刻给一堆改善方法，先让对方感到这状态被理解了"],"sources":["who.int","apa.org","nhs.uk"],"clinicalStatus":"approved"},
  {"id":"exhaustion-that-sleep-cant-fix","title":"睡了还是累的那种累","tags":["过劳","身心耗竭","身体信号"],"keywords":["过劳","累到睡不醒","睡了还是累","一直很疲惫","起不来床","浑身没力气","头疼","肩颈酸","失眠又困","注意力涣散","记不住事","脑子转不动","情绪麻木","提不起精神","周末也缓不过来","身体被掏空","慢性疲劳"],"content":"你说睡再多也补不回来,这不是你想多了。当一个人长期顶着压力,累就不只是缺觉那么简单,它会钻进身体里,变成醒不来的疲惫、酸胀的肩颈、转不动的脑子、记不住的小事,连情绪都跟着发木。这些不是你装出来的,是身体在替你喊停。它扛了很久,现在用这种方式告诉你它需要喘口气。你不用先证明自己真的很累才配休息。这种缓不过来本身,就已经是够分量的信号了。今天能让身体松一点的,哪怕只是早点躺下,都算数。","guidance":["把身体症状如实接住，承认这种累是真实的，不质疑也不轻描淡写","不做任何病因判断或医疗建议，只把症状理解为需要休息的信号","如果身体不适持续或加重，温和地提醒可以去找医生看看，但不替对方下结论"],"sources":["nhs.uk","mayoclinic.org","who.int"],"clinicalStatus":"approved"},
  {"id":"not-all-your-fault","title":"不是你一个人的问题","tags":["工作压力","环境因素","去自责"],"keywords":["工作压力大","压力山大","活太多干不完","任务压死人","没人帮","没人支持","说了不算","做不了主","付出没人看见","没有认可","要求又高又模糊","不知道到底要我干嘛","领导画饼","环境太压抑","职场不公平","想辞职又不敢"],"content":"你一直在找自己哪里没做好,可我听下来,压在你身上的有很多根本不在你手里。活太多、能调动的资源太少、出了事没人帮你扛、明明很拼却没人看见、要你做的事又高又模糊、连一点能自己说了算的余地都没有。这些是环境在往人身上压,不是你能力的问题。一个人长期待在这样的地方,谁都会被磨到没电。看清这一点不是让你认命,是想让你别再把环境的重量,全算到自己头上。你已经在一个很难的局里,撑了很久了。","guidance":["帮对方把可控的与不可控的分开，减轻把系统性压力全归到自己身上的倾向","认可对方的付出，尤其是那些没被看见、没被回报的部分","不替对方做留下还是离开的决定，只陪他把处境看得更清楚一点"],"sources":["apa.org","nhs.uk","who.int"],"clinicalStatus":"approved"},
  {"id":"permission-to-switch-off","title":"你可以真的下班","tags":["休息的正当性","边界","切断"],"keywords":["下班还在想工作","停不下来","脑子一直在转","睡前还回消息","不敢关手机","一休息就内疚","歇着就有罪恶感","觉得自己在偷懒","停下来就慌","随时待命","周末也在加班","不敢请假","不敢拒绝","学不会说不","感觉自己不配休息"],"content":"下班了脑子还在转,睡前还忍不住点开消息,一旦停下来反而心慌,好像歇着就是偷懒。我想轻轻反驳你一句,让自己彻底离开工作一段时间,不是放纵,是人本来就需要的。要从这种长期紧绷里缓过来,得有那么一段时间,你既不在做工作,也不在想工作,真正断开。这不是奖励,不用先把活全干完、先证明自己够格才配拥有。你可以给自己定一条线,比如到点不再看工作消息,或者吃饭的时候不接电话。那条线不是任性,是在保护一个快没电的你。歇下来这件事,你本来就有资格。","guidance":["正面回应休息时的内疚感，把休息重新定义为正当需求而非奖励或偷懒","可以陪对方想一条具体、低门槛的边界，但由对方来定，不强加","不催对方一步到位，哪怕只是先断开十分钟也值得肯定"],"sources":["nhs.uk","apa.org","mind.org.uk"],"clinicalStatus":"approved"},
  {"id":"small-recovery-counts","title":"回血可以从很小开始","tags":["休息","恢复","可执行"],"keywords":["怎么缓过来","怎么恢复","怎么充电","没时间休息","休息也不知道干嘛","提不起兴趣","什么都不想做","周末躺一天还是累","想请假又怕耽误","怎么回血","怎么照顾自己","太累了想躺平","需要喘口气","怎么放松","想逃离工作"],"content":"你问怎么才能缓过来,又觉得自己根本没那个时间和力气。那我们就不从大动作开始。能让你回一点血的,常常是些很小的事,好好吃顿饭,出去走几步,睡前早一点躺下,或者花一点时间做件你自己喜欢、跟工作无关的事。哪怕只有十分钟,也是在给快空了的电池充一点点。如果实在撑不住,能停一阵、彻底离开工作去喘口气,也是完全合理的选择,不是逃避。你不用一下子把自己修好,先挑一件今天做得到的小事,从那儿开始就行。","guidance":["把恢复拆成小到能立刻做的一步，降低对方的执行门槛","提议时给选项而不是命令，让对方挑一件做得到的就好","如果对方需要更长的喘息或停工，正常化这个选择，不评判为逃避"],"sources":["nhs.uk","apa.org","mayoclinic.org"],"clinicalStatus":"approved"},
  {"id":"lean-on-someone","title":"这事不用一个人扛","tags":["社会支持","求助","工作压力"],"keywords":["不想麻烦别人","没人能说","憋着","一个人扛","说出来怕被笑","怕被当成抱怨","孤立无援","不知道找谁","想找人聊聊","要不要跟领导说","要不要找同事","怕被觉得不行","撑不住了","需要帮忙又开不了口"],"content":"你习惯什么都自己憋着,怕说出来是给人添麻烦,又怕被当成只会抱怨。可一直一个人扛,那份重量只会越压越实。把心里的事跟你信得过的人讲一讲,同事、朋友、家里人都行,不一定能马上解决什么,但有人听着、有人懂,那份累会松一点。如果压力是工作本身带来的,找你的上级聊一聊也不是示弱,有时候说开了,事情才有得调整的空间。开口求助不代表你不行,反而是你还在认真照顾自己的证明。要不要,我们先一起想想,这话可以跟谁说。","guidance":["回应对方对求助的顾虑，把开口说出来重新框定为有力量而非软弱","可以陪对方想具体能找谁，朋友、家人或上级，由对方选择","如果对方提到与上级沟通，鼓励但不替他设计话术或施压"],"sources":["nhs.uk","apa.org","mind.org.uk"],"clinicalStatus":"approved"},
  {"id":"meaning-beyond-output","title":"你不只是你做出来的东西","tags":["价值与意义","自我认同","去羞耻"],"keywords":["觉得自己没价值","不产出就慌","工作就是我的全部","效率低就否定自己","做不出成绩","怀疑工作的意义","不知道为什么而忙","感觉自己是工具","没成就感","做什么都没意思","价值感低","不创造就觉得自己没用","存在感靠工作","活得很空"],"content":"倦怠到后面,常常会冒出一个声音,觉得自己做不出东西就没用了,好像你这个人的价值,全系在产出上。我想跟你掰一掰这句话。一个人长期被消耗,本来就会觉得怎么干都不顶用,这是被磨出来的感觉,不是你真实的分量。你的价值不是靠每天交出多少来证明的,你累的时候、慢下来的时候、什么都没产出的时候,你也还是你。如果你开始怀疑这么忙到底为了什么,那不是矫情,是你心里有些更要紧的东西在提醒你它们被晾太久了。我们可以慢慢一起看看,那些对你真正重要的,是什么。","guidance":["把对方的价值和工作产出解绑，强调人的分量不由效率或成果决定","把效能感下降理解为长期消耗的结果，而非对方真实价值的证据","如果对方在追问意义，陪他探索在乎什么，不急于给答案或方向"],"sources":["who.int","apa.org"],"clinicalStatus":"approved"},
  {"id":"perfectionism-never-good-enough","title":"怎么做都不够好","tags":["完美主义","自我价值","高标准"],"keywords":["永远不够好","怎么做都不满意","总觉得做得差","对自己要求太高","差一点就全毁了","别人都说挺好我自己不信","总盯着没做好的地方","做完了也开心不起来","苛刻","对自己太严","完美主义","强迫自己做到最好","怎么努力都达不到标准","看不到自己的好"],"content":"你好像把那根线画得特别高,然后一直用它量自己,量来量去都是差一截。别人说还不错,你心里那个声音却只盯着没做到的地方,好像哪怕九十九分,那缺的一分也能把整件事抹掉。这种累很真实,因为你不是不在乎,是太在乎了,在乎到一点瑕疵都像是在说你这个人不行。我想跟你慢慢分开两件事:一件是这次这件事做得怎么样,另一件是你这个人值不值得。它们其实没绑在一起,只是被你绑久了,松开会有点不习惯。要不先找一件今天的小事,试着用对朋友的那个标准看它一眼,看看会不会松一点。","guidance":["先接住那份累,别急着反驳他的高标准,标准背后往往是怕自己不被认可","帮他把这一件事做得好不好,和他这个人好不好,轻轻分开","可以问他会怎么评价做了同样事情的朋友,让他听见自己对别人宽容得多","不替他下结论说你已经很好了,而是请他自己找一处今天还过得去的地方"],"sources":["nhs.uk","youngminds.org.uk","apa.org"],"clinicalStatus":"approved"},
  {"id":"fear-of-starting","title":"迟迟不敢开始","tags":["害怕开始","拖延","情绪回避"],"keywords":["不敢开始","一直拖着不动","打开文件就关掉","盯着空白页发呆","迟迟下不了手","想到要做就烦","明明知道该做却动不了","卡在第一步","开头最难","准备半天还没开始","越拖越焦虑","怕做不好干脆不做","起手太重"],"content":"我猜你不是懒,你是站在门口反复想象推开门会看到什么,越想越重,重到迈不出那一步。拖着的时候其实没轻松多少对吧,那点喘息很短,后面又被焦虑追上来。这件事难,常常不是它本身有多难,是开始的那一下顶着一团说不清的情绪,可能是怕做砸,可能是嫌烦,可能是没底。你不用先把那团情绪解决掉再动,顺序可以反过来。把第一步切到小得有点好笑的程度,小到不值得逃,比如就写一行字,就打开那个文档看一眼。动起来之后,那团堵着的东西常常会自己散一点。要不你跟我说,这件事最小最小的第一下,是什么。","guidance":["点明拖着并不真的让人轻松,松一口气很快又被焦虑追上","帮他把开始这件事和那团没说出口的情绪分开看,怕的往往不是任务本身","和他一起把第一步切到小得不值得逃避,降低起步的门槛","强调先动一点点,情绪常常会跟着松,而不是等情绪好了才动"],"sources":["apa.org","mcleanhospital.org","mcgraw.princeton.edu"],"clinicalStatus":"approved"},
  {"id":"all-or-nothing-thinking","title":"全或无的想法","tags":["全或无思维","完美主义","极端化"],"keywords":["不完美就是失败","要么做到最好要么不做","差一点就全完了","没有中间地带","非黑即白","做不到一百分就放弃","一步错满盘皆输","破罐破摔","今天没做好这一天就废了","全有或全无","极端","要么全要么不要","一点没达到就觉得整个崩了"],"content":"听起来你心里那把尺只有两个刻度,满分,或者失败,中间那一大片全被划掉了。所以差一点点,在你那儿就等于全毁,今天有一件没做成,整天就被判了死刑。这种想法走起来特别累,因为现实几乎没有满分的时候,你等于让自己长期住在失败那一格里。可大多数事情其实是有颜色的,不是非黑即白,是一片一片的灰,有做成的部分,有没做到的部分,它们可以同时是真的。我不是要你一下子接受七十分,只是想陪你在那两个刻度中间,试着标出一个还行的位置,先看看它存不存在。","guidance":["帮他看见那把尺只有满分和失败两格,中间被自己划掉了","温和指出按这个标准,人几乎只能长期待在失败那一格,这是它累人的地方","引导他承认一件事可以同时有做成的部分和没做到的部分","不强推一下子接受及格,而是陪他在两个极端之间找一个还行的中间点"],"sources":["ncbi.nlm.nih.gov","nhs.uk","apa.org"],"clinicalStatus":"approved"},
  {"id":"good-enough-instead-of-perfect","title":"够好就行","tags":["完美主义","降低标准","实用应对"],"keywords":["怎么才算够好","总想再改改","改到最后改不动了","不舍得交出去","总觉得还能更好","纠结细节出不来","什么都想做到满分","停不下来","完成不了因为想完美","及格就行做不到","放过自己","差不多就行","标准能不能低一点"],"content":"你是不是有过那种时候,东西其实已经能用了,你还在一遍遍改,改到自己都烦,却还是不敢松手交出去。我懂那个不敢,松手好像就等于承认它不够好,等于承认你不够好。可不是所有事都值得你这样耗。有些事就让它过去,扫一眼就行,真正重要的那几件,够好,而不是完美,因为完美这东西没人真的够得着,你一直瞄着它,只会一直差着。够好是一种本事,是知道在哪儿停。要不我们挑一件你正死磕的事,一起想想它停在哪儿就算够了,提前把那条线画出来,而不是改到精疲力尽才被迫停。","guidance":["接住那份不敢松手,松手对他而言像在承认自己不够好","帮他区分哪些事值得用力,哪些扫一眼就能过,不必件件满分","把够好说成一种知道在哪儿停的本事,而不是妥协或失败","陪他提前给具体一件事画出够了的那条线,而不是耗到精疲力尽"],"sources":["nhs.uk","apa.org","youngminds.org.uk"],"clinicalStatus":"approved"},
  {"id":"self-compassion-after-failing","title":"搞砸之后怎么对自己","tags":["自我关怀","自我批评","失败后"],"keywords":["搞砸了好自责","做错了一直骂自己","失败后很难受","对自己太狠","犯了错过不去","复盘到深夜","一直想自己哪里不好","无法原谅自己","做不好就惩罚自己","自我攻击","怎么安慰自己","失败后走不出来","反复责怪自己"],"content":"你刚搞砸一件事,现在心里那个声音是不是正不停地数落你,把你哪儿不好翻来覆去地说。我想拦它一下。我知道你觉得狠狠骂自己一顿,下次才能长记性,可它其实是反着来的,你越是在搞砸之后攻击自己,下次反而越容易回到老样子,越容易再拖再躲。真正能让你重新站起来的,是另一种对自己的话,就像你的好朋友刚搞砸,你不会冲他喊你怎么这么没用,你会说没事,这次是难了点,我们看看接下来怎么办。这种话不是放纵,是让你有力气再来一次。要不你试着,把刚才骂自己那句,换成你会对朋友说的那句。","guidance":["先识别他正在自我数落,温和地拦一下那个声音","点破狠狠责备自己会长记性其实是反的,自责往往让人更容易再次逃避","把善待自己说成有力气再来一次,而不是放纵或找借口","请他把骂自己的那句话,换成会对刚搞砸的朋友说的话"],"sources":["apa.org","ncbi.nlm.nih.gov","mcleanhospital.org"],"clinicalStatus":"approved"},
  {"id":"open-questions-let-them-say-more","title":"用开放式问题，让对方多说一点","tags":["倾听","提问方式","陪伴开场"],"keywords":["不知道怎么开口","怎么问他","怎么回复才不尴尬","对方只回嗯","聊不下去","他不爱说话","怎么让她多说点","问什么","开场白","怎么接话","对方很闷","话题终结者","怎么关心人","他说没事","想了解他怎么了","怕问错"],"content":"比起问能用一个字答完的话,多问那种需要他展开说的。少问你还好吗、是不是不开心,这种他一句没事就堵回来了。可以换成,这几天到底是什么样子的,能跟我讲讲吗。或者,刚才你说累,是哪种累。把球轻轻递过去,让他自己挑想说的那一头。如果他只回了半句,别急着追问下一个,停一下,等一等,他常常会自己接着往下说。你问得越具体、越不像审问,他越容易开口。","guidance":["用需要展开回答的问法，避免只能答是或否、好或不好的封闭问题","顺着对方刚说的某个词往下问，比如他说累就问哪种累，而不是跳到新话题","问完给出停顿，不要连着抛第二个问题，给对方组织语言的时间"],"sources":["samaritans.org","nhs.uk"],"clinicalStatus":"approved"},
  {"id":"listen-dont-fix","title":"先听，别急着给建议或解决","tags":["倾听","不说教","克制"],"keywords":["忍不住想给建议","总想帮他解决","该劝他吗","我说多了","想讲道理","怎么安慰才对","他不听劝","我是不是太唠叨","想替他出主意","讲我自己的经历","你应该","我建议你","怎么帮上忙","插不上话","想纠正他想法","听他倾诉"],"content":"他开口说了之后,最该做的就是听,而不是马上接你应该怎样、要不然你试试。很多时候他不是来找方案的,是想有个人听他把这口气说完。别用你自己的经历去盖过他的,别急着把他的难过翻译成一个待解决的问题。你可以确认有没有听懂,但别打断,也别塞答案进去。建议忍住,先让他说完,光是被认真听着,对他已经是松一口气的事。","guidance":["对方倾诉时先不给建议、不下判断、不抢着分析，让他把话说完整","不要用我当年也这样把话题拉到自己身上，焦点留在对方","可以复述确认有没有理解对，但不要打断或直接给解决方案"],"sources":["samaritans.org","nhs.uk","mayoclinic.org"],"clinicalStatus":"approved"},
  {"id":"reflect-it-back","title":"把他说的，再轻轻说回去","tags":["倾听","回应技巧","被听见"],"keywords":["怎么让他觉得被听到","回应不知道说什么","复述","怎么接","不知道怎么搭话","他说完我冷场","怎么表示我在听","怕说错话","回话很干","怎么共情","让对方感觉被理解","我懂你","说回去","镜映","怎么回应情绪"],"content":"他说完一段,你不用急着评价,可以先把你听到的、他最想让你接住的那部分,用自己的话说回去。比如他讲了一堆,你说,听起来这阵子你一个人扛了很多,是这样吗。说回去不是复读,是让他知道你真的在听、而且听懂了。如果说得不准,他会纠正你,那也很好,等于你们又靠近了一步。别加你自己的解读和评判,就贴着他原本的意思说。","guidance":["用自己的话把对方核心的感受说回去，确认你接住了重点","说回去时贴着对方原意，不要掺入你的评判或重新定义他的感受","如果复述得不准，让对方修正，把这当成更理解他的机会而非出错"],"sources":["samaritans.org"],"clinicalStatus":"approved"},
  {"id":"validate-the-feeling","title":"认下他的感受，哪怕你不完全认同","tags":["接纳情绪","不评判","验证感受"],"keywords":["怎么安慰难过的人","他觉得自己没用","我不认同他想法怎么办","怎么共情但不撒谎","他钻牛角尖","觉得他想多了","怎么回应负面情绪","他说自己很差劲","认可他的感受","怎么让他好受点","他在哭","情绪很重","怎么接住情绪","别否定他","他说撑不住"],"content":"你不用同意他对自己的每个评价,也能认下他此刻的难受。他说我太没用了,你不必附和,也不必反驳成你哪有,你可以说,这么想着的时候,一定特别沉吧。重点是承认这份感受是真的、是有分量的,而不是急着纠正它、淡化它、或者把它解释掉。被这样认下来之后,情绪往往会松一点,他反而更能喘口气。先让感受有地方落,再说别的。","guidance":["承认对方此刻的情绪是真实、合理的，不必同意他对自己或事情的判断","避免你想多了、没那么糟、别难过这类否定或淡化感受的话","先让情绪被接住，不要急着纠正认知或给出反驳"],"sources":["mind.org.uk","mayoclinic.org","mentalhealth.org.uk"],"clinicalStatus":"approved"},
  {"id":"let-silence-breathe","title":"允许沉默，不用把空白填满","tags":["陪伴节奏","沉默","在场"],"keywords":["冷场了怎么办","他不说话","沉默好尴尬","不知道说什么就慌","怕安静","他半天不回","要不要催他","怎么陪着","静下来","停顿","他在组织语言","我话太多","怎么给空间","安静的陪伴","他需要时间"],"content":"他半天没接话,你先别慌着去填那段安静。沉默不一定是坏事,常常是他在心里把话理顺、或者鼓起劲说下一句。这时候你越急着抛话题,反而越打断他。你可以就安安静静待着,让他知道你不急、你在。有时候光是有人陪着、不催不赶,就够他慢慢把堵着的那口气吐出来。沉默也是一种回应,不是非得说点什么才算陪着他。","guidance":["出现停顿时不要急着用新话题填补，给对方整理和开口的空间","把安静当成陪伴的一部分，传达我不急、我在这里","对方迟迟不回也别催，沉默里他可能正在鼓起勇气往下说"],"sources":["samaritans.org"],"clinicalStatus":"approved"},
  {"id":"presence-not-rescue","title":"陪着就好，不用把他修好","tags":["在场","不强求","现实的希望"],"keywords":["我帮不了他好焦虑","感觉很无力","他还是没好转","我是不是没用","怎么才能让他好起来","他把自己关起来","他不理我","别往心里去","我做得不够吗","怎么给希望","空洞安慰","你一定会好的","他说没意义","陪伴有用吗","他推开我","撑不下去了"],"content":"你不用负责把他修好,也修不好,这不是你的失职。他往回缩、不回消息,多半是那股低落在作怪,不是冲你来的,别太往心里去。你能做的,是别消失,时不时发个消息、约个见面,让他知道有人还在。也别用你一定会好起来这种空话糊过去,那反而让他觉得没被听懂。如果要给一点盼头,就贴着实情轻轻说,这种状态是会变的,你不用一个人扛,我陪你慢慢来。","guidance":["接受自己无法立刻让对方好起来，把目标放在持续在场而非修复他","对方退缩或不回应时不要往心里去,那通常是状态使然，保持温和的联系","避免你一定会好的这类空洞保证，要给希望就贴着现实、轻量地给，并强调他不用独自承受"],"sources":["mayoclinic.org","nhs.uk","nimh.nih.gov","mind.org.uk"],"clinicalStatus":"approved"}
];

// Stable text used to build a card's embedding (kept for an optional future vector
// path; current retrieval is keyword-based and uses the fields directly).
export function cardEmbedText(card: KnowledgeCard): string {
  return [card.title, card.content, card.keywords.join(" "), card.tags.join(" ")].join("\n");
}
